-- Schema for Domain: inventory | Business: Retail | Version: v2_mvm
-- Generated on: 2026-06-24 00:49:12

-- ========= DATABASE =========
CREATE DATABASE IF NOT EXISTS `vibe_retail_v1`.`inventory` COMMENT 'Manages real-time and historical stock positions across all nodes including stores, DCs, and MFCs. Owns on-hand quantities, SKU-level tracking, shrinkage monitoring, dead stock identification, weeks of supply (WOS), sell-through rates, replenishment triggers, cycle counts, and RFID-based tracking. Supports VMI (Vendor Managed Inventory), inventory valuation (COGS), and real-time inventory visibility for omnichannel fulfillment.';

-- ========= TABLES =========
CREATE OR REPLACE TABLE `vibe_retail_v1`.`inventory`.`stock_position` (
    `stock_position_id` BIGINT COMMENT 'Unique surrogate identifier for each stock position record representing a SKU-node combination at a point in time. Primary key for the stock_position data product in the Databricks Silver Layer.',
    `inventory_node_id` BIGINT COMMENT 'Reference to the inventory node (store, Distribution Center (DC), Micro-Fulfillment Center (MFC), or dark store) where this stock position is held. Supports omnichannel fulfillment visibility across all network nodes.',
    `lot_id` BIGINT COMMENT 'Foreign key linking to inventory.lot. Business justification: stock_position has a batch_number string attribute indicating lot-tracked inventory. Adding lot_id as a proper FK to the lot master record normalizes this relationship, enabling expiry date management',
    `reorder_policy_id` BIGINT COMMENT 'Foreign key linking to inventory.reorder_policy. Business justification: A stock position at a SKU-location level is governed by a reorder policy that defines replenishment parameters. Linking stock_position to reorder_policy enables direct comparison of current on-hand qu',
    `sku_id` BIGINT COMMENT 'Reference to the SKU (Stock Keeping Unit) for which this stock position is recorded. Links to the product master in the Product Information Management (PIM) system and Informatica MDM golden record.',
    `sku_price_id` BIGINT COMMENT 'Foreign key linking to pricing.sku_price. Business justification: Retail inventory valuation (retail method of accounting) requires linking each stock position to its active selling price. Inventory planners and finance teams use this to compute on-hand retail value',
    `uom_id` BIGINT COMMENT 'Foreign key linking to product.uom. Business justification: stock_position.unit_of_measure is a denormalized text field. Linking to product.uom enforces valid UOM codes, supports UOM conversion for inventory valuation reports, and ensures consistency with the ',
    `available_to_promise_qty` DECIMAL(18,2) COMMENT 'Quantity of the SKU available to commit to new customer orders or fulfillment requests. Calculated as on-hand minus reserved, damaged, and quarantine quantities. Authoritative ATP signal consumed by Salesforce Commerce Cloud for omnichannel order promising (BOPIS, ROPIS, Ship-from-Store).',
    `avg_daily_sales_qty` DECIMAL(18,2) COMMENT 'Rolling average quantity of the SKU sold per day at this node, calculated from SAP Customer Activity Repository (CAR) POS transaction data. Used to compute Weeks of Supply (WOS), reorder point, and safety stock. Input to Blue Yonder Demand Planning forecasts.',
    `batch_number` STRING COMMENT 'Supplier or manufacturer batch/lot number for the current inventory of this SKU at this node. Required for batch-managed products (food, pharmaceuticals, cosmetics) to support FDA recall traceability, CPSC compliance, and Return to Vendor (RTV) processing.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this stock position record was first created in the Databricks Silver Layer. Supports data lineage, audit trail, and GDPR/CCPA data lifecycle management requirements.',
    `currency_code` STRING COMMENT 'Three-letter ISO 4217 currency code for the unit cost and inventory valuation amounts (e.g., USD, GBP, EUR). Supports multi-currency operations across international retail markets.. Valid values are `^[A-Z]{3}$`',
    `damaged_qty` DECIMAL(18,2) COMMENT 'Quantity of the SKU identified as damaged, defective, or unsellable at the inventory node. Excluded from Available-to-Promise (ATP) calculations. Tracked for shrinkage reporting, Return to Vendor (RTV) processing, and COGS (Cost of Goods Sold) write-down.',
    `expiry_date` DATE COMMENT 'Expiration or best-before date of the current inventory batch for perishable or date-sensitive SKUs (grocery, pharmacy, cosmetics). Used for FEFO (First Expired First Out) rotation, FDA food safety compliance, and proactive markdown or disposal before expiry.',
    `in_transit_qty` DECIMAL(18,2) COMMENT 'Quantity of the SKU currently in transit from a supplier, Distribution Center (DC), or another node and expected to arrive at this inventory node. Sourced from Blue Yonder Demand Planning and SAP S/4HANA WM transfer orders. Used for future ATP projection.',
    `inventory_valuation_method` STRING COMMENT 'Accounting method used to value this SKUs inventory for financial reporting. FIFO (First In First Out), LIFO (Last In First Out), WAC (Weighted Average Cost), standard_cost, or retail_method. Governed by FASB ASC 330 and reported in financial P&L statements.. Valid values are `FIFO|LIFO|WAC|standard_cost|retail_method`',
    `is_dead_stock` BOOLEAN COMMENT 'Flag indicating whether this SKU at this node is classified as dead stock — unsold, obsolete inventory with no recent sales velocity. True when sell-through rate is zero and weeks of supply exceeds the dead stock threshold. Triggers markdown or clearance actions.',
    `is_rfid_tracked` BOOLEAN COMMENT 'Indicates whether this SKU at this node is tracked using RFID (Radio Frequency Identification) technology for real-time inventory visibility. True enables automated cycle counts and reduces manual scanning overhead. Relevant for apparel and high-value electronics categories.',
    `is_vmi` BOOLEAN COMMENT 'Indicates whether this SKU-node stock position is managed under a Vendor Managed Inventory (VMI) agreement, where the supplier is responsible for maintaining stock levels. When true, replenishment is supplier-initiated via EDI (Electronic Data Interchange) rather than retailer-triggered.',
    `last_adjustment_date` DATE COMMENT 'Date of the most recent manual or system-generated inventory adjustment (positive or negative) for this SKU at this node. Adjustments include shrinkage write-offs, cycle count corrections, and damage write-downs posted in SAP S/4HANA MM.',
    `last_cycle_count_date` DATE COMMENT 'Date of the most recent physical cycle count or inventory audit performed for this SKU at this node. Used to assess on-hand quantity accuracy, identify shrinkage, and schedule next count. Supports OSHA and internal audit compliance for inventory accuracy.',
    `last_goods_receipt_date` DATE COMMENT 'Date of the most recent goods receipt (inbound delivery) that updated the on-hand quantity for this SKU at this node. Sourced from SAP S/4HANA MM goods receipt postings and Manhattan Associates WMS inbound transactions. Used for freshness and lead time analysis.',
    `last_sale_date` DATE COMMENT 'Date of the most recent Point of Sale (POS) or e-commerce sale transaction that depleted stock for this SKU at this node. Sourced from SAP Customer Activity Repository (CAR). Used for dead stock identification, velocity scoring, and markdown trigger analysis.',
    `max_stock_qty` DECIMAL(18,2) COMMENT 'Maximum allowable on-hand quantity for this SKU at this node, used to prevent overstock and optimize shelf/storage capacity. Defined in Oracle Retail Merchandising System (ORMS) and used by replenishment planning to cap order quantities within Open-to-Buy (OTB) constraints.',
    `on_hand_qty` DECIMAL(18,2) COMMENT 'Total physical quantity of the SKU currently present at the inventory node, including all stock categories (sellable, reserved, damaged). Sourced from Manhattan Associates WMS goods receipt and adjustment transactions. Core metric for inventory visibility.',
    `on_order_qty` DECIMAL(18,2) COMMENT 'Quantity of the SKU on open purchase orders or replenishment orders placed with suppliers but not yet shipped. Sourced from Oracle Retail Merchandising System (ORMS) purchase order lines. Represents future supply commitment within the Open-to-Buy (OTB) budget.',
    `position_status` STRING COMMENT 'Current lifecycle status of the stock position record. Active: normal sellable stock; frozen: temporarily locked pending investigation; quarantine: damaged or suspect stock held for quality review; blocked: SAP-blocked stock not available for sale; closed: position deactivated (zero stock, node closed).. Valid values are `active|frozen|quarantine|blocked|closed`',
    `position_timestamp` TIMESTAMP COMMENT 'The precise date and time at which this stock position snapshot was captured or last updated. Represents the real-world event time of the inventory state. Critical for real-time ATP (Available-to-Promise) accuracy and omnichannel fulfillment SLA compliance.',
    `quarantine_qty` DECIMAL(18,2) COMMENT 'Quantity of the SKU placed in quarantine pending quality inspection, regulatory hold, or recall investigation. Separate from damaged stock. Relevant for FDA food safety holds, CPSC recall compliance, and supplier quality disputes.',
    `reorder_point_qty` DECIMAL(18,2) COMMENT 'Minimum on-hand quantity threshold at which a replenishment order is automatically triggered for this SKU at this node. Calculated by Blue Yonder Demand Planning based on lead time, demand velocity, and safety stock parameters. Core input to replenishment trigger logic.',
    `replenishment_status` STRING COMMENT 'Current replenishment workflow status for this SKU-node combination. normal: no action needed; triggered: reorder point breached, order pending; in_progress: replenishment order placed and open; suspended: replenishment paused (e.g., seasonal end, discontinuation); vmi: under Vendor Managed Inventory (VMI) control.. Valid values are `normal|triggered|in_progress|suspended|vmı`',
    `reserved_qty` DECIMAL(18,2) COMMENT 'Quantity of the SKU reserved against confirmed customer orders, BOPIS (Buy Online Pick Up In Store), ROPIS (Reserve Online Pick Up In Store), or internal transfer orders. Not available for new ATP commitments until reservation is released or fulfilled.',
    `safety_stock_qty` DECIMAL(18,2) COMMENT 'Buffer stock quantity maintained above the reorder point to protect against demand variability and supply lead time uncertainty. Set by Blue Yonder Demand Planning. Prevents stockouts during peak demand or supplier delays.',
    `sell_through_rate` DECIMAL(18,2) COMMENT 'Percentage of received inventory that has been sold within a defined period, expressed as a decimal (e.g., 0.7500 = 75%). Key performance indicator for assortment efficiency, markdown timing, and dead stock identification. Calculated from SAP Customer Activity Repository (CAR) POS data.',
    `shrinkage_qty` DECIMAL(18,2) COMMENT 'Cumulative quantity of inventory loss attributed to shrinkage (theft, administrative error, vendor fraud, or damage) since the last cycle count or physical inventory. Used for shrinkage monitoring, loss prevention analytics, and COGS adjustment reporting.',
    `source_record_reference` STRING COMMENT 'The native record identifier from the originating operational system (e.g., SAP material document number, Manhattan Associates WMS inventory record ID). Enables traceability back to the system of record for reconciliation, audit, and EDI dispute resolution.',
    `source_system_code` STRING COMMENT 'Code identifying the operational system of record that originated this stock position record. SAP_S4: SAP S/4HANA; ORMS: Oracle Retail Merchandising System; MAWMS: Manhattan Associates WMS; BYOND: Blue Yonder Demand Planning; SFCC: Salesforce Commerce Cloud; CAR: SAP Customer Activity Repository. Supports data lineage and Master Data Management (MDM) reconciliation.. Valid values are `SAP_S4|ORMS|MAWMS|BYOND|SFCC|CAR`',
    `storage_location_code` STRING COMMENT 'Specific storage location, bin, aisle, or zone within the inventory node where this SKU is physically stored. Sourced from Manhattan Associates WMS. Used for pick/pack/ship operations, cycle counts, and planogram (POG) compliance in store operations.. Valid values are `^[A-Z0-9_-]{1,30}$`',
    `unit_cost` DECIMAL(18,2) COMMENT 'Standard cost per unit of the SKU used for inventory valuation and Cost of Goods Sold (COGS) calculation. Sourced from SAP S/4HANA FI/CO module. Confidential as it reflects supplier pricing and margin strategy. Used for GMROI (Gross Margin Return on Investment) analysis.',
    `upc` STRING COMMENT 'Universal Product Code (UPC) or European Article Number (EAN) barcode identifier for the SKU. Used for Point of Sale (POS) scanning, RFID tracking, and GS1-compliant product identification across the supply chain.. Valid values are `^[0-9]{12,14}$`',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent update to this stock position record in the Databricks Silver Layer. Used for incremental data processing, change data capture (CDC), and audit trail compliance.',
    `velocity_band` STRING COMMENT 'ABC/D velocity classification of the SKU at this node based on sales frequency and volume. A: fast-moving (top sellers); B: medium-moving; C: slow-moving; D: very slow or non-moving (dead stock candidate). Used for replenishment prioritization, planogram slotting, and markdown strategy.. Valid values are `A|B|C|D`',
    `weeks_of_supply` DECIMAL(18,2) COMMENT 'Number of weeks the current on-hand quantity is projected to last based on the current average weekly sales velocity. Key inventory health metric (WOS) used by merchants and planners to identify overstock, understock, and dead stock situations.',
    CONSTRAINT pk_stock_position PRIMARY KEY(`stock_position_id`)
) COMMENT 'Real-time on-hand stock position for every SKU at each inventory node (store, DC, MFC, dark store). Captures on-hand quantity, available-to-promise (ATP), reserved quantity, in-transit quantity, on-order quantity, damaged/quarantine quantity, and velocity indicators. Authoritative SSOT for current inventory levels consumed by omnichannel fulfillment (ATP/promising), replenishment triggers, and store operations. Updated by goods receipts, sales depletions, adjustments, transfers, and reservations.';

CREATE OR REPLACE TABLE `vibe_retail_v1`.`inventory`.`stock_ledger` (
    `stock_ledger_id` BIGINT COMMENT 'Unique surrogate identifier for each stock ledger transaction record. Primary key for the perpetual inventory ledger at the SKU-location-date level.',
    `fulfillment_line_id` BIGINT COMMENT 'Foreign key linking to fulfillment.fulfillment_line. Business justification: Each fulfillment line pick generates a stock ledger entry. Line-level traceability between inventory movements and fulfillment lines is required for short-pick shrinkage detection, COGS allocation per',
    `goods_receipt_id` BIGINT COMMENT 'Foreign key linking to inventory.goods_receipt. Business justification: Goods receipts generate stock ledger entries recording the inventory increase at the receiving node. stock_ledger has reference_document_number and reference_document_type string fields that generical',
    `inventory_node_id` BIGINT COMMENT 'Foreign key linking to inventory.inventory_node. Business justification: Every stock movement transaction in the perpetual ledger occurs at an inventory node (store, DC, MFC). stock_ledger currently references inventory.location via location_id, but inventory_node is the autho',
    `location_id` BIGINT COMMENT 'Reference to the inventory node (store, Distribution Center (DC), Micro-Fulfillment Center (MFC), or dark store) where the stock movement occurred.',
    `lot_id` BIGINT COMMENT 'Foreign key linking to inventory.lot. Business justification: stock_ledger has a lot_number string attribute for lot-tracked movements. Replacing this with a proper FK lot_id to the lot master record normalizes lot tracking in the perpetual ledger, enabling full',
    `markdown_id` BIGINT COMMENT 'Foreign key linking to pricing.markdown. Business justification: Markdown events generate stock ledger entries recording retail value write-downs. Linking stock_ledger to markdown_id allows retail-method accounting systems to reconcile markdown transactions against',
    `fulfillment_order_id` BIGINT COMMENT 'Foreign key linking to fulfillment.fulfillment_order. Business justification: Fulfillment orders trigger inventory movement postings (goods issue, pick, ship). Linking stock_ledger to fulfillment_order enables fulfillment-driven inventory movement reporting, COGS reconciliation',
    `outbound_order_id` BIGINT COMMENT 'Foreign key linking to supplychain.outbound_order. Business justification: DC outbound operations: when a DC ships to a store via an outbound_order, stock_ledger entries record the inventory deduction. Retail DC inventory controllers need to trace stock_ledger outbound movem',
    `price_change_id` BIGINT COMMENT 'Foreign key linking to pricing.price_change. Business justification: Under the retail inventory method, price change events generate stock ledger entries (retail value write-ups/write-downs). Linking stock_ledger to price_change enables retail accounting systems to tra',
    `promo_campaign_id` BIGINT COMMENT 'Foreign key linking to promotion.promo_campaign. Business justification: Promotional lift analysis requires attributing inventory movements (sales, markdowns) to specific campaigns. Enables campaign-level sell-through reporting, promotional shrinkage tracking, and vendor c',
    `receiving_event_id` BIGINT COMMENT 'Foreign key linking to supplychain.receiving_event. Business justification: DC receiving operations: when goods are unloaded and received (receiving_event), stock_ledger entries are created to record the inventory movement. Retail DC inventory accountants need to trace every ',
    `reversed_transaction_stock_ledger_id` BIGINT COMMENT 'Self-referencing identifier pointing to the original stock_ledger_id that this record reverses. Populated only when reversal_flag = True. Enables bidirectional audit trail linking between original and reversal entries.',
    `shipment_id` BIGINT COMMENT 'Foreign key linking to fulfillment.shipment. Business justification: Shipment completion triggers goods-issue stock ledger postings. Linking stock_ledger to shipment enables shipment-level inventory cost reconciliation, carrier charge vs. inventory cost variance report',
    `sku_id` BIGINT COMMENT 'Reference to the SKU (Stock Keeping Unit) involved in this stock movement transaction. Links to the product master for item-level inventory tracking.',
    `sku_price_id` BIGINT COMMENT 'Foreign key linking to pricing.sku_price. Business justification: Financial reconciliation requires linking inventory movements to pricing effective at transaction time. COGS calculations, margin analysis, and GL posting validation depend on capturing the price-at-t',
    `stock_transfer_id` BIGINT COMMENT 'Foreign key linking to inventory.stock_transfer. Business justification: Stock transfer movements generate stock ledger entries (debit at source node, credit at destination node). stock_ledger has reference_document_number and reference_document_type string fields that gen',
    `uom_id` BIGINT COMMENT 'Foreign key linking to product.uom. Business justification: stock_ledger.unit_of_measure is a denormalized text field. Stock ledger entries drive financial inventory valuation; linking to product.uom ensures UOM integrity for cost accounting, audit trails, and',
    `vendor_id` BIGINT COMMENT 'Reference to the supplier associated with this stock movement, applicable for receipt and Direct Store Delivery (DSD) transactions. Null for internal transfers and sales depletions.',
    `channel` STRING COMMENT 'The omnichannel fulfillment channel through which this stock movement was triggered. STORE = in-store POS sale; ECOMMERCE = online order depletion; BOPIS = Buy Online Pick Up In Store; SHIP_FROM_STORE = store-as-fulfillment-center; DC = Distribution Center; MFC = Micro-Fulfillment Center; DARK_STORE = fulfillment-only location. [ENUM-REF-CANDIDATE: STORE|ECOMMERCE|BOPIS|SHIP_FROM_STORE|DC|MFC|DARK_STORE — 7 candidates stripped; promote to reference product]',
    `created_timestamp` TIMESTAMP COMMENT 'The timestamp when this stock ledger record was first created in the data platform. Represents the system audit creation time, distinct from the business transaction_timestamp. Used for data lineage, audit trail, and Silver layer processing tracking.',
    `currency_code` STRING COMMENT 'Three-letter ISO 4217 currency code in which unit_cost, extended_cost, unit_retail_price, and extended_retail_value are denominated (e.g., USD, EUR, GBP). Supports multi-currency retail operations.. Valid values are `^[A-Z]{3}$`',
    `dead_stock_flag` BOOLEAN COMMENT 'Indicates whether this stock movement is associated with dead stock (unsold, obsolete inventory being written off or liquidated). True = dead stock write-off or clearance movement. Supports inventory health reporting and markdown decision-making.',
    `dsd_flag` BOOLEAN COMMENT 'Indicates whether this receipt transaction was fulfilled via Direct Store Delivery (DSD), where the supplier delivers directly to the store bypassing the Distribution Center (DC). True = DSD transaction. Impacts supply chain routing and vendor compliance tracking.',
    `expiry_date` DATE COMMENT 'The expiration or best-before date of the inventory units involved in this transaction. Applicable for perishable grocery, pharmaceutical, and health/beauty products. Used for FEFO (First Expired First Out) rotation, dead stock identification, and FDA compliance.',
    `extended_cost` DECIMAL(18,2) COMMENT 'Total cost value of this stock movement, calculated as movement_quantity multiplied by unit_cost. Represents the financial impact on inventory valuation and feeds the general ledger Cost of Goods Sold (COGS) account. Used for financial reconciliation.',
    `extended_retail_value` DECIMAL(18,2) COMMENT 'Total retail value of this stock movement, calculated as movement_quantity multiplied by unit_retail_price. Used in the retail inventory method for inventory valuation and supports gross margin return on investment (GMROI) reporting.',
    `fiscal_period` STRING COMMENT 'The retail fiscal period (year and period number, e.g., 2024-P01) to which this stock movement is attributed for financial reporting and inventory reconciliation. Supports 4-4-5 and 4-5-4 retail calendar structures.. Valid values are `^[0-9]{4}-P(0[1-9]|1[0-6])$`',
    `movement_quantity` DECIMAL(18,2) COMMENT 'The quantity of units moved in this transaction. Positive values indicate stock increases (receipts, returns, transfer-in); negative values indicate stock decreases (sales, write-offs, transfer-out). Expressed in the SKUs base unit of measure.',
    `movement_reason_code` STRING COMMENT 'Standardized reason code providing additional context for the stock movement (e.g., VENDOR_RETURN, DAMAGED_GOODS, CYCLE_COUNT_VARIANCE, THEFT_SHRINKAGE, EXPIRED_PRODUCT, PROMOTIONAL_WRITE_DOWN). Supports shrinkage analysis and loss prevention reporting. [ENUM-REF-CANDIDATE: VENDOR_RETURN|DAMAGED_GOODS|CYCLE_COUNT_VARIANCE|THEFT_SHRINKAGE|EXPIRED_PRODUCT|PROMOTIONAL_WRITE_DOWN|CUSTOMER_RETURN|INTER_DC_TRANSFER — promote to reference product]',
    `notes` STRING COMMENT 'Free-text field for additional context or commentary on this stock movement, entered by warehouse staff, store associates, or system processes (e.g., cycle count discrepancy explanation, damage description, special handling notes). Supports operational investigation and audit.',
    `on_hand_quantity_after` DECIMAL(18,2) COMMENT 'The total on-hand inventory quantity for this SKU at this location immediately after this transaction was applied. Represents the running balance of the perpetual inventory ledger and is the authoritative stock position for omnichannel fulfillment visibility.',
    `on_hand_quantity_before` DECIMAL(18,2) COMMENT 'The total on-hand inventory quantity for this SKU at this location immediately before this transaction was applied. Enables point-in-time inventory reconstruction and audit trail validation of the perpetual ledger.',
    `posting_date` DATE COMMENT 'The accounting date on which this stock movement is posted to the general ledger and inventory valuation records. May differ from transaction_timestamp due to cut-off processing, period-end adjustments, or delayed DSD confirmations.',
    `reference_document_number` STRING COMMENT 'The source document number from the originating business transaction that triggered this stock movement (e.g., Purchase Order number, Transfer Order number, POS receipt number, Return Merchandise Authorization (RMA) number). Enables end-to-end traceability.',
    `reference_document_type` STRING COMMENT 'The type of source document associated with this stock movement (e.g., PURCHASE_ORDER, TRANSFER_ORDER, POS_RECEIPT, RMA = Return Merchandise Authorization, CYCLE_COUNT, WRITE_OFF_ORDER). Enables document-level drill-through for audit and reconciliation.. Valid values are `PURCHASE_ORDER|TRANSFER_ORDER|POS_RECEIPT|RMA|CYCLE_COUNT|WRITE_OFF_ORDER`',
    `reversal_flag` BOOLEAN COMMENT 'Indicates whether this stock ledger entry is a reversal (counter-entry) of a previously posted transaction. True = this record reverses a prior movement. Used to identify corrective entries and maintain a clean audit trail for financial reconciliation.',
    `rfid_tracked` BOOLEAN COMMENT 'Indicates whether this stock movement was captured or validated using Radio Frequency Identification (RFID) technology. True = RFID-confirmed movement. Supports inventory accuracy benchmarking and RFID program performance reporting.',
    `serial_number` STRING COMMENT 'The unique serial number of the specific inventory unit involved in this transaction. Applicable for high-value electronics, appliances, and serialized items. Supports specific identification costing, warranty tracking, and CPSC recall management.',
    `shrinkage_flag` BOOLEAN COMMENT 'Indicates whether this stock movement represents inventory shrinkage (loss due to theft, damage, administrative error, or vendor fraud). True = shrinkage event. Used for shrinkage monitoring, loss prevention analytics, and CPSC/NRF compliance reporting.',
    `source_system_code` STRING COMMENT 'Identifies the operational system of record that originated this stock ledger transaction (e.g., SAP_S4 = SAP S/4HANA Retail, ORMS = Oracle Retail Merchandising System, MANHATTAN_WMS = Manhattan Associates WMS, SFCC = Salesforce Commerce Cloud, SAP_CAR = SAP Customer Activity Repository). Supports data lineage and reconciliation.. Valid values are `SAP_S4|ORMS|MANHATTAN_WMS|SFCC|SAP_CAR|MANUAL`',
    `transaction_number` STRING COMMENT 'Externally-known business identifier for this stock movement transaction, sourced from the originating system (e.g., SAP material document number, ORMS transaction reference). Used for cross-system reconciliation and audit tracing.',
    `transaction_status` STRING COMMENT 'Current lifecycle state of the stock ledger transaction. POSTED = confirmed and applied to on-hand balance; PENDING = awaiting confirmation; REVERSED = corrected by a counter-entry; VOIDED = cancelled before posting; ERROR = failed validation.. Valid values are `POSTED|PENDING|REVERSED|VOIDED|ERROR`',
    `transaction_timestamp` TIMESTAMP COMMENT 'The precise real-world date and time when the stock movement event occurred (e.g., POS scan time, receiving dock timestamp, cycle count completion time). This is the principal business event time, distinct from system audit timestamps.',
    `transaction_type` STRING COMMENT 'Classification of the stock movement event driving this ledger entry. RECEIPT = inbound from supplier or DC; SALE = Point of Sale (POS) depletion; TRANSFER_IN/OUT = inter-location movement; ADJUSTMENT = cycle count correction; RETURN = customer or Return to Vendor (RTV); WRITE_OFF = shrinkage or dead stock removal. [ENUM-REF-CANDIDATE: RECEIPT|SALE|TRANSFER_IN|TRANSFER_OUT|ADJUSTMENT|RETURN|WRITE_OFF|DSD_RECEIPT|MARKDOWN_WRITE_DOWN|CYCLE_COUNT — promote to reference product]',
    `unit_cost` DECIMAL(18,2) COMMENT 'The per-unit cost (Cost of Goods Sold - COGS) applied to this stock movement at the time of the transaction. Used for inventory valuation under FIFO, Weighted Average Cost (WAC), or retail inventory method. Sourced from the active cost layer in SAP S/4HANA.',
    `unit_retail_price` DECIMAL(18,2) COMMENT 'The retail selling price per unit at the time of the transaction. Used for inventory valuation under the retail inventory method and for calculating gross margin. Supports Average Unit Retail (AUR) analytics and sell-through rate calculations.',
    `updated_timestamp` TIMESTAMP COMMENT 'The timestamp when this stock ledger record was last modified in the data platform (e.g., due to a reversal posting, status correction, or revaluation). Used for change data capture, audit trail, and incremental processing in the Databricks Lakehouse Silver layer.',
    `valuation_method` STRING COMMENT 'The inventory costing method applied to this stock movement for financial valuation purposes. FIFO = First In First Out; WAC = Weighted Average Cost; RETAIL_METHOD = retail inventory method; LIFO = Last In First Out (where permitted); SPECIFIC_ID = specific identification for high-value items.. Valid values are `FIFO|WAC|RETAIL_METHOD|LIFO|SPECIFIC_ID`',
    `vmf_flag` BOOLEAN COMMENT 'Indicates whether this stock movement is part of a Vendor Managed Inventory (VMI) arrangement, where the supplier is responsible for maintaining stock levels. True = VMI-managed transaction. Impacts replenishment ownership and supplier performance tracking.',
    CONSTRAINT pk_stock_ledger PRIMARY KEY(`stock_ledger_id`)
) COMMENT 'Perpetual inventory ledger capturing every stock movement transaction at the SKU-location-date level. Records receipts, sales depletions, transfers, adjustments, returns, and write-offs with quantity, unit cost (COGS), and extended value. Supports inventory valuation methods (FIFO, WAC, retail method), shrinkage tracking, and financial reconciliation with the general ledger. Authoritative SSOT for inventory value and movement history within the inventory domain.';

CREATE OR REPLACE TABLE `vibe_retail_v1`.`inventory`.`inventory_node` (
    `inventory_node_id` BIGINT COMMENT 'Unique surrogate identifier for every physical or logical inventory-holding location in the retail network (stores, DCs, MFCs, dark stores, vendor-managed locations, in-transit nodes). Primary key of this master record.',
    `cost_zone_id` BIGINT COMMENT 'Foreign key linking to pricing.cost_zone. Business justification: Inventory nodes are assigned to cost zones that determine landed cost, freight factors, and duty rates applicable to that node. This assignment drives cost_price calculations for replenishment and goo',
    `dc_facility_id` BIGINT COMMENT 'Add column dc_facility_id (BIGINT) to supplychain.inventory_node with FK to supplychain.dc_facility.dc_facility_id because inventory nodes at distribution centers should reference the DC facility. P15: connect_table: supplychain.inventory_node*',
    `location_id` BIGINT COMMENT 'Add column location_id (BIGINT) to store.inventory_node with FK to store.location.location_id because inventory nodes represent physical locations. P14: connect_table: store.inventory_node** - add column location_id (BIGINT) with FK',
    `price_zone_id` BIGINT COMMENT 'Foreign key linking to pricing.price_zone. Business justification: Every retail store/DC node belongs to a price zone that determines which sku_price records are active for that location. Price zone assignment to inventory nodes is fundamental to retail pricing execu',
    `address_line1` STRING COMMENT 'Primary street address of the inventory node facility. Used for carrier routing, last-mile delivery coordination, and regulatory filings.',
    `address_line2` STRING COMMENT 'Secondary address detail (suite, dock number, building identifier) for the inventory node facility.',
    `city` STRING COMMENT 'City in which the inventory node is located. Used for geographic reporting, tax jurisdiction assignment, and carrier zone mapping.',
    `close_date` DATE COMMENT 'Calendar date on which the inventory node was permanently closed or decommissioned. Null for active nodes. Used for historical inventory reporting and asset disposal tracking.',
    `country_code` STRING COMMENT 'Three-letter ISO 3166-1 alpha-3 country code for the node location. Governs applicable regulatory frameworks (FDA, CPSC, GDPR/CCPA), currency, and customs rules.. Valid values are `^[A-Z]{3}$`',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this inventory node master record was first created in the system, in ISO 8601 format (yyyy-MM-ddTHH:mm:ss.SSSXXX). Supports MDM audit trails and data lineage in Informatica MDM.',
    `cycle_count_frequency` STRING COMMENT 'Scheduled frequency at which physical inventory cycle counts are conducted at this node. Drives WMS task scheduling and shrinkage monitoring cadence.. Valid values are `daily|weekly|monthly|quarterly|annual`',
    `district_code` STRING COMMENT 'Internal district code within a region, used for field management span-of-control, district-level KPI reporting, and workforce scheduling via Workday HCM.. Valid values are `^[A-Z0-9_-]{2,15}$`',
    `dock_door_count` STRING COMMENT 'Number of inbound/outbound dock doors at the node. Determines receiving throughput capacity, inbound appointment scheduling windows, and cross-docking feasibility in Manhattan Associates WMS.',
    `format_code` STRING COMMENT 'Retail format identifier assigned to the node (e.g., HYPERMARKET, DISCOUNT, DEPT_STORE, ECOMM_FC). Drives assortment breadth/depth rules in ORMS and planogram (POG) assignments.. Valid values are `^[A-Z0-9_-]{2,20}$`',
    `gln` STRING COMMENT 'GS1-issued 13-digit Global Location Number uniquely identifying this node in the global supply chain. Used in EDI transactions (ASC X12 / EDIFACT), RFID-based receiving, and supplier communications.. Valid values are `^[0-9]{13}$`',
    `is_bopis_enabled` BOOLEAN COMMENT 'Indicates whether the node supports Buy Online Pick Up In Store (BOPIS) fulfillment. Drives order routing logic in the OMS and Salesforce Commerce Cloud checkout flow.',
    `is_drop_ship_origin` BOOLEAN COMMENT 'Indicates whether this node acts as a drop-ship origin point where a vendor ships directly to the end customer on behalf of the retailer, bypassing DC inventory.',
    `is_rfid_enabled` BOOLEAN COMMENT 'Indicates whether the node is equipped with RFID infrastructure for real-time inventory tracking, cycle count automation, and shrinkage reduction.',
    `is_ropis_enabled` BOOLEAN COMMENT 'Indicates whether the node supports Reserve Online Pick Up In Store (ROPIS), allowing customers to reserve items online and collect without pre-payment.',
    `is_ship_from_store_enabled` BOOLEAN COMMENT 'Indicates whether the node is configured as a Ship-from-Store (SFS) fulfillment center, allowing it to pick, pack, and ship e-commerce orders directly to customers.',
    `is_vmi_enabled` BOOLEAN COMMENT 'Indicates whether this node participates in a Vendor Managed Inventory (VMI) program where the supplier is responsible for maintaining stock levels.',
    `last_cycle_count_date` DATE COMMENT 'Date of the most recent physical inventory cycle count performed at this node. Used to assess inventory accuracy, schedule next count, and monitor shrinkage compliance.',
    `last_updated_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent modification to this inventory node master record. Used for change data capture (CDC), MDM synchronization, and Silver Layer incremental processing in Databricks.',
    `latitude` DECIMAL(18,2) COMMENT 'WGS-84 decimal latitude coordinate of the node. Enables geospatial proximity analysis for BOPIS radius calculations, last-mile routing optimization, and store clustering.',
    `longitude` DECIMAL(18,2) COMMENT 'WGS-84 decimal longitude coordinate of the node. Used alongside latitude for geospatial routing, catchment area analysis, and omnichannel fulfillment optimization.',
    `manager_name` STRING COMMENT 'Name of the store manager, DC operations manager, or facility lead responsible for this inventory node. Used for escalation routing, audit accountability, and Workday HCM workforce reporting.',
    `max_sku_capacity` STRING COMMENT 'Maximum number of distinct SKUs (Stock Keeping Units) the node can actively stock based on shelf slots, bin locations, and planogram (POG) configuration. Used in assortment planning and OTB (Open to Buy) calculations.',
    `node_code` STRING COMMENT 'Externally-known alphanumeric business identifier for the node as maintained in SAP S/4HANA WM and Oracle Retail Merchandising System (ORMS). Used in EDI transactions, purchase orders, and replenishment plans to reference the location. Serves as the BUSINESS_IDENTIFIER (MASTER_RESOURCE canonical category).. Valid values are `^[A-Z0-9_-]{2,20}$`',
    `node_name` STRING COMMENT 'Human-readable display name of the inventory node (e.g., Chicago Midway DC, Store #0421 – Oak Park). Used in operational reports, planograms, and WMS screens. Serves as the IDENTITY_LABEL (MASTER_RESOURCE canonical category).',
    `node_type` STRING COMMENT 'Categorical classification of the inventory-holding location. Drives fulfillment capability rules, replenishment logic, and reporting hierarchies. Valid values: store (retail selling floor), distribution_center (DC), micro_fulfillment_center (MFC), dark_store (fulfillment-only), vendor_managed (VMI location), in_transit (goods in movement). Serves as the CLASSIFICATION_OR_TYPE (MASTER_RESOURCE canonical category).. Valid values are `store|distribution_center|micro_fulfillment_center|dark_store|vendor_managed|in_transit`',
    `open_date` DATE COMMENT 'Calendar date on which the inventory node became operationally active and began receiving or fulfilling inventory. Used for comp sales (SSS) eligibility determination and new-store ramp analysis.',
    `operational_status` STRING COMMENT 'Current lifecycle state of the inventory node. Controls whether the node is eligible to receive stock, fulfill orders, or appear in replenishment plans. Serves as the LIFECYCLE_STATUS (MASTER_RESOURCE canonical category).. Valid values are `active|inactive|under_construction|temporarily_closed|decommissioned|planned`',
    `ownership_type` STRING COMMENT 'Legal ownership or operating arrangement for the node facility. Drives lease accounting under FASB ASC 842, asset capitalization rules, and P&L cost allocation.. Valid values are `owned|leased|franchised|licensed|third_party`',
    `phone_number` STRING COMMENT 'Primary operational phone number for the inventory node facility. Used for carrier coordination, inbound appointment confirmation, and emergency contact.. Valid values are `^+?[0-9s-().]{7,20}$`',
    `postal_code` STRING COMMENT 'Postal or ZIP code of the inventory node. Used for carrier zone determination, last-mile delivery routing, and geographic market analysis.. Valid values are `^[A-Z0-9 -]{3,10}$`',
    `primary_dc_node_code` STRING COMMENT 'Node code of the primary Distribution Center (DC) that replenishes this node. Used in replenishment routing, inbound appointment scheduling, and supply chain network optimization.. Valid values are `^[A-Z0-9_-]{2,20}$`',
    `region_code` STRING COMMENT 'Internal geographic region code grouping nodes for regional P&L reporting, district management, and comp sales (SSS) analysis (e.g., MIDWEST, NORTHEAST, WEST_COAST).. Valid values are `^[A-Z0-9_-]{2,15}$`',
    `replenishment_lead_time_days` STRING COMMENT 'Standard number of days from replenishment order placement to stock receipt at this node. Used by Blue Yonder Demand Planning to calculate reorder points, weeks of supply (WOS), and safety stock levels.',
    `safety_stock_days` STRING COMMENT 'Minimum days of supply maintained as safety stock buffer at this node to protect against demand variability and supply disruptions. Feeds Blue Yonder replenishment planning and WOS calculations.',
    `selling_area_sqft` DECIMAL(18,2) COMMENT 'Net selling floor area in square feet, excluding back-of-house, receiving docks, and storage. Used for sales-per-square-foot KPI, planogram space allocation, and GMROI analysis.',
    `state_province` STRING COMMENT 'ISO 3166-2 state or province code for the node location. Drives sales tax rules, labor law compliance, and regional reporting.. Valid values are `^[A-Z]{2,3}$`',
    `subtype` STRING COMMENT 'Secondary classification providing finer granularity within node_type (e.g., hypermarket, department_store, discount_outlet, cross_dock_dc, ambient_dc, cold_chain_dc, ship_from_store_hub). [ENUM-REF-CANDIDATE: hypermarket|department_store|discount_outlet|cross_dock_dc|ambient_dc|cold_chain_dc|ship_from_store_hub|ecommerce_fc — promote to reference product]',
    `temperature_zone` STRING COMMENT 'Storage temperature classification for the node. Governs which SKU categories (grocery, frozen, pharma) can be stocked and drives cold-chain compliance requirements under FDA food safety regulations.. Valid values are `ambient|chilled|frozen|multi_temp`',
    `time_zone` STRING COMMENT 'IANA time zone identifier for the node (e.g., America/Chicago). Critical for accurate timestamp normalization of POS transactions, cycle count scheduling, and SLA window calculations across multi-timezone networks.',
    `total_storage_capacity_sqft` DECIMAL(18,2) COMMENT 'Total physical storage area of the node measured in square feet. Used for capacity planning, space utilization analysis, and GMROI calculations. Serves as the MEASUREMENT_OR_VALUE (MASTER_RESOURCE canonical category).',
    CONSTRAINT pk_inventory_node PRIMARY KEY(`inventory_node_id`)
) COMMENT '[SSOT Owner] Authoritative source for inventory-holding locations (stores, DCs, 3PL nodes). Defines physical attributes, capabilities, and capacity of each node in the inventory network.';

CREATE OR REPLACE TABLE `vibe_retail_v1`.`inventory`.`replenishment_order` (
    `replenishment_order_id` BIGINT COMMENT 'Unique surrogate identifier for the replenishment order record in the Silver Layer lakehouse. Primary key for this entity.',
    `cost_price_id` BIGINT COMMENT 'Foreign key linking to pricing.cost_price. Business justification: Purchase order costing and landed cost validation require linking replenishment orders to contracted vendor cost structures. Enables variance analysis between ordered cost and actual invoice cost, and',
    `demand_forecast_id` BIGINT COMMENT 'Reference to the demand forecast record that informed the replenishment quantity calculation. Links to the Blue Yonder Demand Planning forecast used to size this order.',
    `inventory_node_id` BIGINT COMMENT 'Reference to the receiving fulfillment node (store, DC, or MFC) where replenished inventory will be delivered. Drives last-mile delivery routing and receiving dock scheduling.',
    `inbound_shipment_id` BIGINT COMMENT 'Foreign key linking to supplychain.inbound_shipment. Business justification: Replenishment order fulfillment tracking: when a vendor ships against a replenishment_order, an inbound_shipment is created. Retail replenishment managers track expected_delivery_date vs. actual_arriv',
    `lead_time_agreement_id` BIGINT COMMENT 'Foreign key linking to supplier.lead_time_agreement. Business justification: Replenishment orders must reference the governing lead time SLA to enable on-time delivery compliance reporting and exception alerting. Retail supply chain teams track whether each order was fulfilled',
    `outbound_order_id` BIGINT COMMENT 'Foreign key linking to supplychain.outbound_order. Business justification: Store replenishment from DC: a replenishment_order (store perspective) is fulfilled by an outbound_order (DC perspective). Retail store operations and DC operations teams need to reconcile these two r',
    `primary_replenishment_inventory_node_id` BIGINT COMMENT 'Reference to the originating fulfillment node (Distribution Center, Micro-Fulfillment Center, or supplier location) from which inventory will be shipped. Supports omnichannel inventory routing logic.',
    `promo_campaign_id` BIGINT COMMENT 'Reference to the promotion event that drove this replenishment order, when trigger_type is promotional. Links to the promotion master to support promotional inventory planning and post-event analysis. Nullable for non-promotional orders.',
    `purchase_order_id` BIGINT COMMENT 'Reference to the associated purchase order in SAP S/4HANA MM or Oracle Retail Merchandising System (ORMS) when the replenishment order results in a supplier PO. Nullable for internal DC-to-store transfers.',
    `reorder_policy_id` BIGINT COMMENT 'Reference to the reorder policy that triggered this replenishment order. Links to the replenishment plan thresholds (reorder point, safety stock, max stock) configured in Blue Yonder Demand Planning.',
    `replenishment_plan_id` BIGINT COMMENT 'Foreign key linking to supplychain.replenishment_plan. Business justification: Replenishment execution tracking: a replenishment_order is the execution artifact of a replenishment_plan. Retail buyers and planners need to compare planned vs. actual order quantities and timing. Th',
    `sku_id` BIGINT COMMENT 'Reference to the SKU (Stock Keeping Unit) being replenished. Links to the product master in Oracle Retail Merchandising System (ORMS) and Informatica MDM product golden record.',
    `uom_id` BIGINT COMMENT 'Foreign key linking to product.uom. Business justification: replenishment_order.unit_of_measure is a denormalized text field. Replenishment orders must reference the authoritative UOM for MOQ compliance, vendor ordering units, and purchase order generation — a',
    `vendor_contract_id` BIGINT COMMENT 'Foreign key linking to supplier.vendor_contract. Business justification: Replenishment orders must be placed under an active vendor contract to enforce pricing, MOQ, and payment terms. Retail procurement compliance requires each order to reference the governing contract fo',
    `vendor_id` BIGINT COMMENT 'Reference to the supplier (vendor) fulfilling this replenishment order. Represents the PARTY_REFERENCE for this transaction. Links to the supplier master managed in Informatica MDM and SAP S/4HANA MM vendor master.',
    `vendor_item_id` BIGINT COMMENT 'Foreign key linking to supplier.vendor_item. Business justification: When raising a replenishment order, buyers reference the vendors catalog entry (vendor_item) to confirm pack size, MOQ, and unit cost. This link enables PO accuracy validation and cost capture at ord',
    `actual_delivery_date` DATE COMMENT 'The date the replenishment order was physically received and confirmed at the destination node. Compared against expected_delivery_date to measure supplier on-time delivery performance and SLA compliance.',
    `approved_quantity` DECIMAL(18,2) COMMENT 'The quantity confirmed and approved for fulfillment after supplier acceptance, MOQ compliance checks, and buyer review. May differ from ordered_quantity due to supplier constraints or buyer adjustments.',
    `approved_timestamp` TIMESTAMP COMMENT 'The date and time the replenishment order was approved by the buyer or automatically confirmed by the system. Marks the transition from draft/submitted to approved status in the order lifecycle.',
    `buyer_notes` STRING COMMENT 'Free-text notes entered by the merchandise buyer or replenishment analyst providing context for manual overrides, special handling instructions, or supplier communication details for this replenishment order.',
    `cancellation_reason` STRING COMMENT 'The business reason for cancelling the replenishment order. Overstock = destination node already has sufficient inventory; supplier_oos = supplier cannot fulfill; price_discrepancy = cost mismatch; duplicate_order = order already exists; demand_change = forecast revision eliminated need. Nullable for non-cancelled orders.. Valid values are `overstock|supplier_oos|price_discrepancy|duplicate_order|demand_change|other`',
    `cancelled_timestamp` TIMESTAMP COMMENT 'The date and time the replenishment order was cancelled, if applicable. Nullable for active or completed orders. Used for supplier chargeback processing and demand planning feedback loops.',
    `created_timestamp` TIMESTAMP COMMENT 'Audit timestamp recording when this replenishment order record was first captured in the Silver Layer data platform. Used for data lineage and pipeline monitoring.',
    `currency_code` STRING COMMENT 'Three-letter ISO 4217 currency code for all monetary amounts on this replenishment order (unit_cost, total_order_cost). Supports multi-currency operations for international supplier transactions.. Valid values are `^[A-Z]{3}$`',
    `expected_delivery_date` DATE COMMENT 'The anticipated date on which the replenishment order is expected to arrive at the destination node, calculated from order_date plus lead_time_days. Used for inventory availability planning and receiving dock scheduling.',
    `fulfillment_channel` STRING COMMENT 'The physical supply chain channel through which this replenishment order will be fulfilled. dc_to_store = Distribution Center to store; supplier_to_store = Direct Store Delivery (DSD); supplier_to_dc = inbound to DC; cross_dock = Cross-Docking without DC storage; dsd = Direct Store Delivery; drop_ship = vendor ships directly to end customer. [ENUM-REF-CANDIDATE: dc_to_store|supplier_to_store|supplier_to_dc|cross_dock|dsd|drop_ship — promote to reference product]. Valid values are `dc_to_store|supplier_to_store|supplier_to_dc|cross_dock|dsd|drop_ship`',
    `is_emergency` BOOLEAN COMMENT 'Indicates whether this replenishment order was flagged as an emergency order due to an imminent or active out-of-stock situation. Emergency orders bypass standard lead time and approval workflows. True = emergency; False = standard.',
    `is_vmi` BOOLEAN COMMENT 'Indicates whether this replenishment order is managed under a Vendor Managed Inventory (VMI) agreement where the supplier is responsible for maintaining stock levels at the destination node. True = VMI order; False = retailer-managed replenishment.',
    `lead_time_days` STRING COMMENT 'The supplier Lead Time in calendar days from order submission to expected delivery at the destination node. Sourced from SAP S/4HANA MM purchasing info record or Blue Yonder Demand Planning supplier master. Used to calculate expected_delivery_date and Weeks of Supply (WOS).',
    `moq` DECIMAL(18,2) COMMENT 'The Minimum Order Quantity (MOQ) stipulated by the supplier for this SKU at the time the replenishment order was created. Used to validate that ordered_quantity meets supplier contractual requirements. Sourced from SAP S/4HANA MM purchasing info record.',
    `moq_compliant` BOOLEAN COMMENT 'Indicates whether the ordered_quantity meets or exceeds the suppliers Minimum Order Quantity (MOQ) requirement. True = compliant; False = below MOQ threshold, requiring buyer review or override.',
    `order_date` TIMESTAMP COMMENT 'The principal business event timestamp — the date and time the replenishment order was created and submitted by the demand planning or replenishment system (Blue Yonder or SAP MM). Distinct from audit timestamps.',
    `order_number` STRING COMMENT 'Externally-known business identifier for the replenishment order, sourced from Blue Yonder Demand Planning or SAP S/4HANA MM module. Used for cross-system traceability and supplier communication via EDI.. Valid values are `^RPL-[0-9]{10}$`',
    `order_status` STRING COMMENT 'Current lifecycle state of the replenishment order. Tracks progression from draft creation through approval, shipment, receipt at destination node, and closure. Cancelled indicates the order was voided before fulfillment. [ENUM-REF-CANDIDATE: draft|submitted|approved|in_transit|received|partially_received|cancelled|closed — promote to reference product]',
    `order_type` STRING COMMENT 'Classification of how the replenishment order was triggered. Auto-replenishment is system-generated based on reorder policy thresholds; manual is buyer-initiated; VMI (Vendor Managed Inventory) is supplier-driven; emergency covers urgent out-of-stock situations; cross_dock bypasses DC storage; drop_ship routes directly from vendor to destination. [ENUM-REF-CANDIDATE: auto_replenishment|manual|vmi|emergency|cross_dock|drop_ship — promote to reference product]. Valid values are `auto_replenishment|manual|vmi|emergency|cross_dock|drop_ship`',
    `ordered_quantity` DECIMAL(18,2) COMMENT 'The quantity of the SKU originally requested in the replenishment order, expressed in the SKUs base unit of measure (e.g., each, case, pallet). This is the raw demand signal before supplier approval or MOQ adjustment.',
    `priority_level` STRING COMMENT 'Business priority assigned to this replenishment order, used to sequence fulfillment and allocate DC resources. Critical = imminent out-of-stock risk; high = elevated demand or promotional support; standard = routine replenishment; low = opportunistic or pre-build.. Valid values are `critical|high|standard|low`',
    `received_quantity` DECIMAL(18,2) COMMENT 'The actual quantity of the SKU physically received and confirmed at the destination node. Used to calculate fill rate and identify short shipments. Populated upon goods receipt in Manhattan Associates WMS or SAP S/4HANA WM.',
    `source_system_order_ref` STRING COMMENT 'The native order identifier from the originating source system (e.g., SAP MM document number, Blue Yonder order ID, ORMS order number). Enables reverse lookup and reconciliation with the system of record.',
    `total_order_cost` DECIMAL(18,2) COMMENT 'The total cost of the replenishment order calculated as approved_quantity multiplied by unit_cost. Represents the financial commitment for this replenishment event. Used for Open to Buy (OTB) budget tracking and P&L reporting.',
    `trigger_type` STRING COMMENT 'The mechanism that triggered this replenishment order. reorder_point = on-hand fell below reorder point threshold; min_max = inventory fell below minimum level; days_of_supply = Weeks of Supply (WOS) fell below threshold; manual_override = buyer-initiated; vmi_signal = Vendor Managed Inventory (VMI) supplier signal; promotional = triggered by upcoming promotion event. [ENUM-REF-CANDIDATE: reorder_point|min_max|days_of_supply|manual_override|vmi_signal|promotional — promote to reference product]. Valid values are `reorder_point|min_max|days_of_supply|manual_override|vmi_signal|promotional`',
    `unit_cost` DECIMAL(18,2) COMMENT 'The Cost of Goods Sold (COGS) per unit for this SKU at the time of the replenishment order, sourced from the SAP S/4HANA MM purchasing info record or Oracle Retail Merchandising System (ORMS). Used for inventory valuation and GMROI analysis.',
    `updated_timestamp` TIMESTAMP COMMENT 'Audit timestamp recording when this replenishment order record was last modified in the Silver Layer data platform. Supports change detection and incremental processing.',
    CONSTRAINT pk_replenishment_order PRIMARY KEY(`replenishment_order_id`)
) COMMENT 'Replenishment order records generated by demand planning and replenishment systems to restock SKUs at stores or DCs. Captures order type (auto-replenishment, manual, VMI), source node, destination node, ordered quantity, approved quantity, expected delivery date, lead time, MOQ compliance, and fulfillment status. Tracks the full replenishment lifecycle from trigger (based on reorder_policy thresholds) through receipt at the destination node.';

CREATE OR REPLACE TABLE `vibe_retail_v1`.`inventory`.`cycle_count` (
    `cycle_count_id` BIGINT COMMENT 'Unique system-generated identifier for each cycle count event record at the SKU-location level.',
    `adjustment_id` BIGINT COMMENT 'Reference to the inventory adjustment record created as a result of this cycle count variance exceeding the tolerance threshold. Links the count event to its financial reconciliation record.',
    `department_id` BIGINT COMMENT 'Foreign key linking to store.department. Business justification: Cycle counts are scheduled, executed, and reported by department within a store (e.g., count Apparel dept Q2). Retail loss prevention and inventory accuracy reporting require department-level cycle ',
    `inventory_node_id` BIGINT COMMENT 'Foreign key linking to inventory.inventory_node. Business justification: Cycle counts are physical inventory events conducted at inventory nodes (stores, DCs, MFCs). cycle_count currently references inventory.location via location_id, but inventory_node is the authoritative SS',
    `location_id` BIGINT COMMENT 'Reference to the inventory node (store, Distribution Center (DC), or Micro-Fulfillment Center (MFC)) where the cycle count is being performed.',
    `sku_id` BIGINT COMMENT 'Reference to the specific SKU (Stock Keeping Unit) being counted in this cycle count event.',
    `sku_price_id` BIGINT COMMENT 'Foreign key linking to pricing.sku_price. Business justification: Retail inventory method requires cycle count variance reporting at retail value, not just cost. Linking cycle_count to sku_price enables variance_cost calculation at retail price — a standard retail a',
    `stock_position_id` BIGINT COMMENT 'Foreign key linking to inventory.stock_position. Business justification: A cycle count is a physical verification of the stock position at a specific SKU-location. Linking cycle_count directly to stock_position enables immediate comparison of counted_quantity vs. system_qu',
    `uom_id` BIGINT COMMENT 'Foreign key linking to product.uom. Business justification: cycle_count.unit_of_measure is a denormalized text field. Cycle count variance calculations (variance_cost, variance_quantity) require a validated UOM reference to ensure counted quantities are expres',
    `warehouse_zone_id` BIGINT COMMENT 'Foreign key linking to supplychain.warehouse_zone. Business justification: DC cycle counting is organized by warehouse_zone — zone managers schedule and execute counts by zone. Linking cycle_count to warehouse_zone enables zone-level count frequency tracking, compliance repo',
    `abc_classification` STRING COMMENT 'ABC classification of the SKU at the time of the cycle count, indicating inventory value and velocity tier. A = high-value/high-velocity; B = medium; C = low-value/low-velocity; D = dead stock. Drives count frequency prioritization.. Valid values are `A|B|C|D`',
    `adjustment_generated` BOOLEAN COMMENT 'Indicates whether an inventory_adjustment record has been generated from this cycle count variance. When True, the variance has been posted to the inventory ledger for reconciliation.',
    `approval_timestamp` TIMESTAMP COMMENT 'The date and time when the cycle count result was reviewed and approved by the designated supervisor or manager, completing the approval workflow.',
    `count_device_code` STRING COMMENT 'Identifier of the handheld scanner, mobile device, or RFID reader used to perform the physical count. Supports device-level audit trail and equipment calibration tracking.',
    `count_end_timestamp` TIMESTAMP COMMENT 'The precise date and time when the physical counting activity was completed and the count was submitted by the assigned counter.',
    `count_frequency` STRING COMMENT 'The scheduled counting frequency for this SKU-location combination, typically driven by ABC classification or velocity. High-velocity A-items are counted more frequently than slow-moving C-items.. Valid values are `daily|weekly|monthly|quarterly|annual|event_driven`',
    `count_notes` STRING COMMENT 'Free-text field for the counter or supervisor to record observations, exceptions, or explanations related to the cycle count result (e.g., damaged packaging, items in transit, display stock not included).',
    `count_number` STRING COMMENT 'Externally-known business reference number assigned to the cycle count event, used for cross-system tracking and audit trail. Typically generated by the WMS (e.g., Manhattan Associates) or SAP WM module.',
    `count_start_timestamp` TIMESTAMP COMMENT 'The precise date and time when the physical counting activity was initiated by the assigned counter. Used for cycle time analysis and labor tracking.',
    `count_status` STRING COMMENT 'Current workflow state of the cycle count event. scheduled = count is planned but not started; in_progress = counting is underway; completed = physical count recorded; reconciled = variance reviewed and inventory adjustment posted; cancelled = count was voided.. Valid values are `scheduled|in_progress|completed|reconciled|cancelled`',
    `count_type` STRING COMMENT 'Classification of the cycle count method. scheduled = routine planned count; ad_hoc = unplanned triggered count; blind = counter does not see system quantity; directed = WMS-directed count task; rfid_assisted = count performed using Radio Frequency Identification (RFID) technology.. Valid values are `scheduled|ad_hoc|blind|directed|rfid_assisted`',
    `counted_quantity` DECIMAL(18,2) COMMENT 'The actual physical quantity of the SKU observed and recorded by the counter during the cycle count. This is the primary measured outcome of the count event.',
    `created_timestamp` TIMESTAMP COMMENT 'The date and time when this cycle count record was first created in the system, establishing the audit trail for SOX inventory controls.',
    `currency_code` STRING COMMENT 'ISO 4217 three-letter currency code for the monetary values (variance_cost, unit_cost) recorded in this cycle count record (e.g., USD, GBP, EUR).. Valid values are `^[A-Z]{3}$`',
    `fiscal_period` STRING COMMENT 'The retail fiscal period (year and period number, e.g., 2024-P06) during which the cycle count was performed. Used for period-end inventory accuracy reporting and financial close processes.. Valid values are `^[0-9]{4}-P(0[1-9]|1[0-3])$`',
    `planogram_location` STRING COMMENT 'The planogram (POG) shelf position or fixture reference for the SKU at the store location, used to direct the counter to the correct physical location during in-store cycle counts.',
    `recount_number` STRING COMMENT 'Sequential count of how many times this SKU-location has been recounted within the same cycle count event. First count = 1; first recount = 2; etc. Supports escalation workflows when repeated recounts still show variance.',
    `recount_required` BOOLEAN COMMENT 'Indicates whether a recount of this SKU-location is required because the variance exceeded the tolerance threshold or the count was flagged for discrepancy. When True, a follow-up count must be performed before reconciliation.',
    `scheduled_date` DATE COMMENT 'The calendar date on which the cycle count was planned to be performed, as set in the WMS count schedule.',
    `shrinkage_category` STRING COMMENT 'Classification of the root cause of inventory shrinkage identified through this cycle count. Populated during the reconciliation phase when a negative variance is confirmed. Supports shrinkage investigation and loss prevention analytics.. Valid values are `theft|damage|administrative_error|vendor_shortage|unknown`',
    `storage_bin` STRING COMMENT 'The specific warehouse storage bin, shelf, or slot location within the inventory node where the SKU is physically stored and counted. Granular location identifier used by the WMS for directed counting.',
    `system_quantity` DECIMAL(18,2) COMMENT 'The inventory quantity recorded in the Warehouse Management System (WMS) or ERP at the exact time the cycle count was initiated. This is the book quantity against which the physical count is compared.',
    `trigger_reason` STRING COMMENT 'Business reason that initiated this cycle count. Supports shrinkage investigation and root cause analysis. [ENUM-REF-CANDIDATE: routine|negative_inventory|shrinkage_alert|receiving_discrepancy|customer_complaint|audit_request|rfid_discrepancy — promote to reference product]',
    `unit_cost` DECIMAL(18,2) COMMENT 'The Cost of Goods Sold (COGS) unit cost of the SKU at the time the cycle count was performed, used to calculate the financial impact of any inventory variance.',
    `updated_timestamp` TIMESTAMP COMMENT 'The date and time when this cycle count record was last modified, supporting audit trail and change tracking requirements.',
    `variance_cost` DECIMAL(18,2) COMMENT 'The monetary value of the inventory variance, calculated as variance_quantity multiplied by the unit cost at time of count. Expressed in the local operating currency. Used for Cost of Goods Sold (COGS) impact assessment and financial reporting.',
    `variance_percentage` DECIMAL(18,2) COMMENT 'The variance quantity expressed as a percentage of the system on-hand quantity, calculated as (variance_quantity / system_quantity) * 100. Used to assess inventory accuracy and trigger shrinkage investigations when thresholds are exceeded.',
    `variance_quantity` DECIMAL(18,2) COMMENT 'The difference between the physically counted quantity and the system on-hand quantity (counted_quantity minus system_quantity). A negative value indicates shrinkage or loss; a positive value indicates an overcount or unrecorded receipt.',
    `variance_tolerance_pct` DECIMAL(18,2) COMMENT 'The maximum acceptable variance percentage for this SKU-location before a recount or inventory adjustment is triggered. Variances exceeding this threshold generate inventory_adjustment records for reconciliation.',
    CONSTRAINT pk_cycle_count PRIMARY KEY(`cycle_count_id`)
) COMMENT 'Scheduled and ad-hoc physical inventory cycle count events at the SKU-location level. Captures count schedule, assigned counter, counted quantity, system quantity at time of count, variance quantity, variance percentage, count status (scheduled, in-progress, completed, reconciled), and approval workflow. Supports shrinkage investigation, inventory accuracy KPIs, and Sarbanes-Oxley inventory controls. Variances exceeding tolerance thresholds generate inventory_adjustment records for reconciliation.';

CREATE OR REPLACE TABLE `vibe_retail_v1`.`inventory`.`adjustment` (
    `adjustment_id` BIGINT COMMENT 'Unique system-generated identifier for each inventory adjustment record. Serves as the primary key for the adjustment data product and is referenced by the stock ledger and loss prevention systems.',
    `cost_price_id` BIGINT COMMENT 'Foreign key linking to pricing.cost_price. Business justification: Shrinkage and adjustment financial impact calculations require cost basis. GL posting, P&L impact analysis, and loss prevention reporting depend on linking adjustments to the cost structure for accura',
    `fulfillment_line_id` BIGINT COMMENT 'Foreign key linking to fulfillment.fulfillment_line. Business justification: Fulfillment line exceptions (substitution, short-pick, damage at pick) directly trigger inventory adjustments. Line-level adjustment traceability is a standard WMS audit requirement enabling per-line ',
    `inventory_node_id` BIGINT COMMENT 'Foreign key linking to inventory.inventory_node. Business justification: Inventory adjustments (shrinkage, damage, recalls) occur at inventory nodes. adjustment currently references inventory.location via location_id, but inventory_node is the SSOT for inventory-holding locati',
    `location_id` BIGINT COMMENT 'Reference to the specific inventory node (store, Distribution Center (DC), Micro-Fulfillment Center (MFC), or dark store) where the adjustment is being recorded. Supports omnichannel inventory visibility.',
    `lot_id` BIGINT COMMENT 'Foreign key linking to inventory.lot. Business justification: adjustment has a batch_number string attribute for lot-tracked adjustments (e.g., shrinkage of a specific lot, recall-driven adjustments). Replacing this with a proper FK lot_id to the lot master reco',
    `fulfillment_order_id` BIGINT COMMENT 'Foreign key linking to fulfillment.fulfillment_order. Business justification: Fulfillment exceptions (damaged goods, mis-picks, cancellations) trigger inventory adjustments. Linking adjustment to fulfillment_order enables fulfillment-driven shrinkage reporting, exception root-c',
    `pos_transaction_id` BIGINT COMMENT 'Foreign key linking to order.pos_transaction. Business justification: Inventory adjustments for shrinkage, damage, or discrepancies are often discovered during POS operations (cashier finds damaged item, customer returns defective product). Linking adjustment to origina',
    `promo_campaign_id` BIGINT COMMENT 'Foreign key linking to promotion.promo_campaign. Business justification: Promotional markdown adjustments and vendor-funded write-downs must be attributed to campaigns for campaign cost accounting and vendor chargeback reconciliation. Retail finance teams require this link',
    `reversal_of_adjustment_id` BIGINT COMMENT 'Self-referencing identifier pointing to the original adjustment record that this record is reversing. Populated only for reversal entries to maintain a complete audit trail of corrections. Nullable for original (non-reversal) adjustments.',
    `sku_id` BIGINT COMMENT 'Reference to the specific SKU (Stock Keeping Unit) whose inventory quantity is being adjusted. Links to the product master to identify the item at the variant level (size, color, style).',
    `stock_ledger_id` BIGINT COMMENT 'Reference to the corresponding stock ledger entry created when this adjustment was posted. Establishes the audit trail between the adjustment record and the resulting stock position change. Nullable until the adjustment reaches posted status.',
    `uom_id` BIGINT COMMENT 'Foreign key linking to product.uom. Business justification: adjustment.unit_of_measure is a denormalized text field. Inventory adjustments feed shrinkage reporting and financial reconciliation; a validated FK to product.uom ensures adjusted quantities are in t',
    `vendor_id` BIGINT COMMENT 'Reference to the supplier associated with this adjustment, applicable for receiving variances, Return to Vendor (RTV) adjustments, vendor fraud shrinkage, or Direct Store Delivery (DSD) discrepancies. Nullable for non-supplier-related adjustments.',
    `adjusted_quantity` DECIMAL(18,2) COMMENT 'The net quantity change applied to on-hand inventory for the SKU at the specified location. Negative values represent inventory reductions (shrinkage, damage, write-offs); positive values represent inventory additions (found stock, receiving corrections). Expressed in the SKUs unit of measure.',
    `adjustment_number` STRING COMMENT 'Externally visible, human-readable business identifier for the adjustment transaction. Used in audit trails, loss prevention case references, and cross-system reconciliation with SAP S/4HANA and ORMS. Format: ADJ- followed by 10 digits.. Valid values are `^ADJ-[0-9]{10}$`',
    `adjustment_status` STRING COMMENT 'Current workflow lifecycle state of the adjustment record. Controls whether the adjustment has been applied to the stock ledger. posted indicates the adjustment has updated on-hand quantities; reversed indicates a correcting entry was made.. Valid values are `draft|pending_approval|approved|rejected|posted|reversed`',
    `adjustment_timestamp` TIMESTAMP COMMENT 'The principal real-world date and time when the inventory adjustment event occurred (e.g., when shrinkage was detected, when a cycle count discrepancy was identified, when damage was observed). Distinct from system audit timestamps. Format: yyyy-MM-ddTHH:mm:ss.SSSXXX.',
    `approval_status` STRING COMMENT 'Indicates whether the adjustment has been reviewed and approved through the authorization workflow. auto_approved applies to system-generated adjustments below a defined threshold that bypass manual review. Distinct from adjustment_status which tracks the full posting lifecycle.. Valid values are `pending|approved|rejected|auto_approved`',
    `approval_timestamp` TIMESTAMP COMMENT 'Date and time when the adjustment was approved or rejected by the authorizing user. Used for SLA (Service Level Agreement) compliance tracking on adjustment processing turnaround. Format: yyyy-MM-ddTHH:mm:ss.SSSXXX.',
    `cost_impact` DECIMAL(18,2) COMMENT 'Total financial impact of the inventory adjustment on Cost of Goods Sold (COGS), calculated as adjusted_quantity multiplied by unit_cost. Negative values represent write-downs (losses); positive values represent write-ups (gains). Posted to the general ledger via SAP FI/CO integration.',
    `created_timestamp` TIMESTAMP COMMENT 'System audit timestamp recording when the adjustment record was first created in the system. Used for data lineage, audit compliance, and SLA tracking. Format: yyyy-MM-ddTHH:mm:ss.SSSXXX.',
    `currency_code` STRING COMMENT 'Three-letter ISO 4217 currency code in which the cost impact and unit cost are expressed (e.g., USD, GBP, EUR, CAD). Required for multi-currency retail operations and financial consolidation.. Valid values are `^[A-Z]{3}$`',
    `department_code` STRING COMMENT 'The merchandise department code associated with the SKU being adjusted, sourced from the product hierarchy in Oracle Retail Merchandising System (ORMS). Enables shrinkage and adjustment reporting by department for category management and P&L analysis.',
    `detection_method` STRING COMMENT 'The method by which the inventory discrepancy or adjustment need was identified. Supports shrinkage root-cause analysis and RFID (Radio Frequency Identification) program effectiveness measurement. [ENUM-REF-CANDIDATE: cycle_count|physical_inventory|rfid_scan|pos_exception|receiving_audit|system_alert|manual_observation|loss_prevention_investigation — promote to reference product]',
    `expiry_date` DATE COMMENT 'The expiration or best-before date of the inventory being written off, applicable for perishable grocery, food, and pharmaceutical SKUs. Required for FDA food safety compliance and expiry write-off reporting. Nullable for non-perishable items. Format: yyyy-MM-dd.',
    `fiscal_period` STRING COMMENT 'The fiscal accounting period (year and period number) to which this adjustment is attributed for financial reporting and shrinkage rate analysis. Format: YYYY-P## (e.g., 2024-P01 through 2024-P13 for 4-4-5 retail calendar).. Valid values are `^[0-9]{4}-P(0[1-9]|1[0-3])$`',
    `is_shrinkage` BOOLEAN COMMENT 'Boolean flag indicating whether this adjustment represents a shrinkage event (inventory loss due to theft, damage, administrative error, or vendor fraud). Used to filter and aggregate shrinkage metrics for loss prevention reporting and GMROI (Gross Margin Return on Investment) analysis.',
    `is_system_generated` BOOLEAN COMMENT 'Boolean flag indicating whether the adjustment was automatically generated by a system process (e.g., Blue Yonder replenishment system, RFID reconciliation engine, WMS cycle count automation) rather than manually entered by a user.',
    `location_type` STRING COMMENT 'Classification of the inventory node type where the adjustment occurred. Distinguishes between store-level adjustments, Distribution Center (DC) adjustments, Micro-Fulfillment Center (MFC) adjustments, and dark store adjustments for segmented shrinkage and variance reporting.. Valid values are `store|dc|mfc|dark_store|vendor_location`',
    `lp_case_reference` STRING COMMENT 'Reference number linking this inventory adjustment to an active or closed Loss Prevention (LP) investigation case (e.g., shoplifting incident, employee theft case). Nullable — only populated when the adjustment is associated with a formal LP case in Salesforce Service Cloud or a dedicated LP system.',
    `notes` STRING COMMENT 'Free-text field for additional context, observations, or explanations provided by the initiating or authorizing user regarding the inventory adjustment. Supports audit trail completeness and loss prevention investigation documentation.',
    `posting_date` DATE COMMENT 'The accounting date on which the inventory adjustment is posted to the stock ledger and general ledger. May differ from adjustment_timestamp when adjustments are batched or backdated for period-end closing. Format: yyyy-MM-dd.',
    `quantity_after_adjustment` DECIMAL(18,2) COMMENT 'The on-hand inventory quantity for the SKU at the location immediately after this adjustment is applied. Derived at posting time and stored for audit trail and stock ledger reconciliation. Expressed in the SKUs unit of measure.',
    `quantity_before_adjustment` DECIMAL(18,2) COMMENT 'The on-hand inventory quantity for the SKU at the location immediately prior to this adjustment being applied. Captured at the time of adjustment for audit trail completeness and variance analysis. Expressed in the SKUs unit of measure.',
    `reason_category` STRING COMMENT 'High-level classification of why the inventory adjustment is being made. Drives reporting buckets for shrinkage monitoring, COGS (Cost of Goods Sold) impact analysis, and loss prevention dashboards. [ENUM-REF-CANDIDATE: shrinkage|damage|cycle_count_correction|receiving_variance|expiry_write_off|rtv|admin_correction|found_stock — promote to reference product]',
    `reason_sub_category` STRING COMMENT 'Granular sub-classification within the reason category providing specific cause detail. Examples for shrinkage: shoplifting, employee theft, administrative error, vendor fraud. Examples for damage: in-transit damage, handling damage, shelf damage. Feeds loss prevention case analysis and shrinkage root-cause reporting. [ENUM-REF-CANDIDATE: shoplifting|employee_theft|admin_error|vendor_fraud|in_transit_damage|handling_damage|shelf_damage|expired|recalled|mis-ship — promote to reference product]',
    `recall_flag` BOOLEAN COMMENT 'Boolean flag indicating whether this inventory adjustment is associated with a product recall event initiated by the CPSC, FDA, or the retailer. Enables rapid identification and financial quantification of recall-related inventory write-offs.',
    `rfid_tag_count` STRING COMMENT 'Number of RFID (Radio Frequency Identification) tags scanned during the detection event that triggered this adjustment. Populated only for RFID-based detection methods. Supports RFID program accuracy measurement and tag read-rate analysis.',
    `source_document_number` STRING COMMENT 'The reference number of the originating source document (e.g., cycle count ID, RTV authorization number, receiving document number, damage report ID). Enables cross-system traceability and audit trail linkage.',
    `source_document_type` STRING COMMENT 'The type of source business document that triggered or supports this inventory adjustment. Provides traceability back to the originating business process (e.g., cycle count sheet, Return to Vendor (RTV) authorization, receiving document). [ENUM-REF-CANDIDATE: cycle_count|physical_inventory|rtv_authorization|receiving_document|damage_report|expiry_report|pos_exception_report — promote to reference product]',
    `unit_cost` DECIMAL(18,2) COMMENT 'The Cost of Goods Sold (COGS) per unit at the time of adjustment, used to calculate the total cost impact of the inventory change. Sourced from the inventory valuation layer in SAP S/4HANA. Business-confidential as it reflects supplier pricing.',
    `updated_timestamp` TIMESTAMP COMMENT 'System audit timestamp recording when the adjustment record was most recently modified. Tracks approval workflow updates, status changes, and corrections. Format: yyyy-MM-ddTHH:mm:ss.SSSXXX.',
    CONSTRAINT pk_adjustment PRIMARY KEY(`adjustment_id`)
) COMMENT 'Records all inventory quantity adjustments at the SKU-location level including shrinkage events, damage write-downs, cycle count corrections, receiving variances, expiry write-offs, and RTVs. Captures adjustment reason category, sub-reason (e.g., shoplifting, employee theft, admin error for shrinkage), adjusted quantity, cost impact, detection method, authorizing user, approval status, and loss prevention case reference where applicable. Feeds the stock_ledger and serves as the SSOT for all non-transactional inventory changes and shrinkage monitoring.';

CREATE OR REPLACE TABLE `vibe_retail_v1`.`inventory`.`stock_transfer` (
    `stock_transfer_id` BIGINT COMMENT 'Unique system-generated surrogate identifier for each inter-node stock transfer record in the inventory management system.',
    `carrier_id` BIGINT COMMENT 'Reference to the logistics carrier or 3PL (Third-Party Logistics) provider responsible for transporting the stock transfer between nodes. Used for carrier performance analytics and SLA compliance reporting.',
    `cost_price_id` BIGINT COMMENT 'Foreign key linking to pricing.cost_price. Business justification: Transfer accounting and intercompany pricing require cost data for inventory valuation during movement. Store-to-store transfers, DC-to-store shipments, and cross-dock operations need cost basis for f',
    `inventory_node_id` BIGINT COMMENT 'Identifier of the receiving inventory node (store, DC, MFC, or vendor location) to which the stock transfer is directed. Used for inventory receipt confirmation and network replenishment tracking.',
    `lot_id` BIGINT COMMENT 'Foreign key linking to inventory.lot. Business justification: Inter-node stock transfers frequently move specific lots, particularly for perishable or lot-tracked items where FEFO sequencing and expiry management require lot-level transfer tracking. Adding lot_i',
    `fulfillment_order_id` BIGINT COMMENT 'Foreign key linking to fulfillment.fulfillment_order. Business justification: Ship-from-store and store-to-store transfers are initiated to fulfill specific fulfillment orders (BOPIS, ROPIS, SFS). Linking stock_transfer to fulfillment_order enables end-to-end order fulfillment ',
    `order_line_id` BIGINT COMMENT 'Foreign key linking to order.order_line. Business justification: Ship-from-store fulfillment: when an online order line triggers a store-to-customer transfer, the stock_transfer must reference the originating order_line for customer service tracing, SLA compliance ',
    `outbound_order_id` BIGINT COMMENT 'Foreign key linking to supplychain.outbound_order. Business justification: DC-to-store transfer execution: a stock_transfer (inventory movement record) corresponds to an outbound_order (DC shipping execution record). Retail inventory and DC operations teams need this link fo',
    `primary_stock_inventory_node_id` BIGINT COMMENT 'Identifier of the originating inventory node (store, DC, MFC, or vendor location) from which the stock transfer is dispatched. Supports network balancing and omnichannel fulfillment analytics.',
    `promo_campaign_id` BIGINT COMMENT 'Foreign key linking to promotion.promo_campaign. Business justification: Retailers execute targeted inter-store and DC-to-store transfers to concentrate promotional stock at high-traffic locations before campaign launch. Linking stock_transfer to promo_campaign enables pro',
    `purchase_order_id` BIGINT COMMENT 'Reference to the originating purchase order that triggered this stock transfer, applicable for DC-to-store replenishment flows sourced from supplier inbound receipts. Links transfer to procurement context.',
    `replenishment_order_id` BIGINT COMMENT 'Foreign key linking to inventory.replenishment_order. Business justification: A stock transfer is frequently initiated to fulfill a replenishment order — moving inventory from a DC to a store or between nodes as directed by the replenishment system. Linking stock_transfer to re',
    `replenishment_plan_id` BIGINT COMMENT 'Reference to the replenishment plan that generated this stock transfer, linking the physical movement to the demand-driven planning signal from Blue Yonder or Oracle Retail. Supports replenishment accuracy analytics.',
    `shipment_id` BIGINT COMMENT 'Foreign key linking to fulfillment.shipment. Business justification: Inter-node stock transfers that are physically shipped generate carrier shipments. Linking stock_transfer to shipment enables tracking number association, carrier cost allocation to transfer events, a',
    `sku_id` BIGINT COMMENT 'Reference to the specific SKU (Stock Keeping Unit) being transferred. The SKU is the atomic unit of inventory tracking, uniquely identifying a product variant (size, color, style) within the retail assortment.',
    `uom_id` BIGINT COMMENT 'Foreign key linking to product.uom. Business justification: stock_transfer.unit_of_measure is a denormalized text field. Inter-node transfers require validated UOM for transfer_cost calculations, receiving reconciliation, and variance_quantity reporting — all ',
    `actual_receipt_date` DATE COMMENT 'Calendar date on which the stock transfer was physically received and confirmed at the destination node. Compared against expected_receipt_date to measure carrier and DC performance against SLA targets.',
    `created_timestamp` TIMESTAMP COMMENT 'System audit timestamp recording when this stock transfer record was first persisted in the data platform. Used for data lineage, audit trails, and Silver layer ingestion tracking.',
    `currency_code` STRING COMMENT 'ISO 4217 three-letter currency code in which the transfer cost is denominated (e.g., USD, GBP, EUR). Supports multi-currency retail operations across international markets.. Valid values are `^[A-Z]{3}$`',
    `destination_node_type` STRING COMMENT 'Classification of the receiving inventory node. STORE: retail store; DC: distribution center; MFC: micro-fulfillment center; VENDOR: supplier location for RTV; DARK_STORE: fulfillment-only location.. Valid values are `STORE|DC|MFC|VENDOR|DARK_STORE`',
    `expected_receipt_date` DATE COMMENT 'Planned calendar date by which the stock transfer is expected to arrive at the destination node. Used for replenishment planning, weeks of supply (WOS) calculations, and SLA compliance monitoring.',
    `initiated_timestamp` TIMESTAMP COMMENT 'Date and time when the stock transfer record was first created in the system, representing the business event of transfer initiation. Serves as the principal business event timestamp for the transfer lifecycle.',
    `inventory_cost_per_unit` DECIMAL(18,2) COMMENT 'Cost of Goods Sold (COGS) value per unit for the transferred SKU at time of transfer, used for inventory valuation, GMROI calculations, and financial reporting. Sourced from SAP S/4HANA FI/CO standard cost or moving average cost.',
    `is_cross_dock` BOOLEAN COMMENT 'Flag indicating whether this stock transfer is executed as a cross-docking (cross-dock) movement, where inventory is transferred directly from inbound to outbound at the DC without putaway storage. Supports DC throughput and flow-through analytics.',
    `is_ship_from_store` BOOLEAN COMMENT 'Flag indicating whether this stock transfer is part of a ship-from-store (SFS) omnichannel fulfillment flow, where a retail store acts as a fulfillment node dispatching inventory to satisfy an e-commerce or BOPIS order.',
    `is_vendor_managed` BOOLEAN COMMENT 'Flag indicating whether this stock transfer is part of a Vendor Managed Inventory (VMI) program, where the supplier initiates and manages the replenishment transfer rather than the retailers internal planning team.',
    `notes` STRING COMMENT 'Free-text operational notes or comments associated with the stock transfer, capturing exception details, special handling instructions, or carrier communication relevant to the transfer execution.',
    `priority_level` STRING COMMENT 'Operational priority assigned to the stock transfer, influencing pick sequencing, carrier selection, and dispatch scheduling at the DC or store. URGENT transfers may be triggered by stockout alerts or product recalls.. Valid values are `URGENT|HIGH|STANDARD|LOW`',
    `received_quantity` STRING COMMENT 'Actual number of units confirmed received at the destination node upon delivery. May differ from transfer_quantity due to transit damage, shrinkage, or carrier discrepancies. Drives inventory reconciliation and shrinkage monitoring.',
    `rfid_enabled` BOOLEAN COMMENT 'Flag indicating whether this stock transfer was tracked using RFID (Radio Frequency Identification) technology for real-time inventory visibility during transit. Supports RFID-based inventory accuracy programs.',
    `shipment_date` DATE COMMENT 'Calendar date on which the stock transfer was physically dispatched from the source node. Used for lead time calculation, carrier SLA tracking, and inventory in-transit reporting.',
    `source_node_type` STRING COMMENT 'Classification of the originating inventory node. STORE: retail store; DC: distribution center; MFC: micro-fulfillment center; VENDOR: supplier location for RTV or DSD; DARK_STORE: fulfillment-only location.. Valid values are `STORE|DC|MFC|VENDOR|DARK_STORE`',
    `source_system_code` STRING COMMENT 'Code identifying the operational system of record from which this stock transfer record originated. Supports data lineage, reconciliation, and Silver layer provenance tracking across the retail technology stack.. Valid values are `SAP_WM|MANHATTAN_WMS|ORMS|BLUE_YONDER`',
    `tracking_number` STRING COMMENT 'Carrier-assigned shipment tracking number for the stock transfer, enabling real-time in-transit visibility and last-mile delivery monitoring. Used for exception management and carrier SLA validation.',
    `transfer_cost` DECIMAL(18,2) COMMENT 'Total logistics cost incurred for executing this stock transfer, including carrier freight charges, handling fees, and any 3PL surcharges. Used for inventory valuation (COGS), P&L allocation, and supply chain cost optimization.',
    `transfer_number` STRING COMMENT 'Externally-known business reference number for the stock transfer, used for tracking and communication across supply chain partners, carriers, and store operations. Sourced from SAP S/4HANA MM transfer order numbering.. Valid values are `^ST-[0-9]{10}$`',
    `transfer_quantity` STRING COMMENT 'Number of units of the SKU authorized and dispatched in this stock transfer. Represents the planned transfer quantity as recorded at time of transfer creation.',
    `transfer_reason_code` STRING COMMENT 'Business reason code explaining why the stock transfer was initiated. REPLENISHMENT: routine inventory restocking; NETWORK_BALANCE: lateral balancing to address overstock/understock; RTV: return to vendor; RECALL: product safety recall per CPSC; DAMAGE_RETURN: return of damaged goods; OMNICHANNEL: ship-from-store or BOPIS fulfillment support.. Valid values are `REPLENISHMENT|NETWORK_BALANCE|RTV|RECALL|DAMAGE_RETURN|OMNICHANNEL`',
    `transfer_status` STRING COMMENT 'Current lifecycle state of the stock transfer. DRAFT: initiated but not yet dispatched; IN_TRANSIT: shipment dispatched from source node; RECEIVED: confirmed receipt at destination node; CANCELLED: transfer voided before completion; EXCEPTION: discrepancy or damage reported during transit.. Valid values are `DRAFT|IN_TRANSIT|RECEIVED|CANCELLED|EXCEPTION`',
    `transfer_type` STRING COMMENT 'Classification of the inter-node inventory movement. DC_TO_STORE: distribution center replenishment to store; STORE_TO_STORE: lateral balancing between stores; STORE_TO_DC: reverse logistics or consolidation; CROSS_DOCK: direct transfer without storage per cross-docking (DSD) model; RTV: Return to Vendor; MFC_TO_STORE: micro-fulfillment center to store for omnichannel fulfillment (ship-from-store).. Valid values are `DC_TO_STORE|STORE_TO_STORE|STORE_TO_DC|CROSS_DOCK|RTV|MFC_TO_STORE`',
    `upc` STRING COMMENT '12-digit Universal Product Code (UPC) barcode identifier for the transferred SKU, used for scanning and verification during pick, pack, and receipt operations at DC and store nodes.. Valid values are `^[0-9]{12}$`',
    `updated_timestamp` TIMESTAMP COMMENT 'System audit timestamp recording the most recent modification to this stock transfer record, such as status updates, quantity adjustments, or receipt confirmations. Supports change data capture and audit compliance.',
    `variance_quantity` STRING COMMENT 'Difference between transfer_quantity and received_quantity, representing units lost, damaged, or unaccounted for during transit. Positive value indicates shortage; negative indicates overage. Drives shrinkage monitoring and carrier chargeback processes.',
    `variance_reason_code` STRING COMMENT 'Reason code explaining the cause of any quantity variance between dispatched and received units. Used for shrinkage root cause analysis, carrier chargeback (RMA) processing, and inventory reconciliation.. Valid values are `TRANSIT_DAMAGE|CARRIER_LOSS|PICKING_ERROR|OVERAGE|NO_VARIANCE`',
    CONSTRAINT pk_stock_transfer PRIMARY KEY(`stock_transfer_id`)
) COMMENT 'Inter-node stock transfer records capturing movement of inventory between stores, DCs, MFCs, and vendor locations. Captures transfer type (store-to-store, DC-to-store, cross-dock, RTV), source node, destination node, SKU, transfer quantity, shipment date, expected receipt date, actual receipt date, carrier, and transfer status. Supports omnichannel fulfillment (ship-from-store) and network balancing.';

CREATE OR REPLACE TABLE `vibe_retail_v1`.`inventory`.`goods_receipt` (
    `goods_receipt_id` BIGINT COMMENT 'Unique system-generated surrogate identifier for each goods receipt record in the inventory domain. Primary key for the goods_receipt data product.',
    `cost_price_id` BIGINT COMMENT 'Foreign key linking to pricing.cost_price. Business justification: Receiving process validates invoice costs against contracted pricing and updates landed cost. Three-way match (PO-receipt-invoice) depends on linking goods receipt to cost structure for variance detec',
    `inbound_shipment_id` BIGINT COMMENT 'Foreign key linking to supplychain.inbound_shipment. Business justification: ASN-to-receipt matching: goods_receipt is the inventory confirmation of an inbound_shipments arrival. Retail receiving teams match ASNs to receipts for discrepancy resolution. bill_of_lading_number a',
    `inventory_node_id` BIGINT COMMENT 'Reference to the physical location (DC, store, or MFC) where the merchandise was received. Supports inventory accuracy at point of induction and omnichannel fulfillment visibility.',
    `po_line_id` BIGINT COMMENT 'Reference to the specific purchase order line item being received. Enables line-level PO matching, partial receipt tracking, and SKU-level discrepancy analysis.',
    `purchase_order_id` BIGINT COMMENT 'Reference to the parent purchase order against which this goods receipt is posted. Enables PO-to-receipt matching, open order tracking, and three-way match (PO, receipt, invoice) for accounts payable.',
    `receiving_event_id` BIGINT COMMENT 'Foreign key linking to supplychain.receiving_event. Business justification: DC receiving process: receiving_event is the physical unloading/inspection event; goods_receipt is the inventory system record created from it. Retail DC managers need to link these for quality inspec',
    `replenishment_order_id` BIGINT COMMENT 'Foreign key linking to inventory.replenishment_order. Business justification: A goods receipt records the physical arrival of merchandise against a replenishment order (in addition to purchase orders). goods_receipt already has purchase_order_id for PO-based receipts, but lacks',
    `sku_id` BIGINT COMMENT 'Reference to the SKU (Stock Keeping Unit) being received. Links to the product master in Informatica MDM or Oracle Retail Merchandising System for item-level inventory induction.',
    `uom_id` BIGINT COMMENT 'Foreign key linking to product.uom. Business justification: goods_receipt.unit_of_measure is a denormalized text field. Goods receipt drives total_receipt_cost and discrepancy calculations; linking to product.uom ensures received quantities are validated again',
    `vendor_id` BIGINT COMMENT 'Reference to the supplier or vendor from whom the merchandise was received. Links to the supplier master record in Informatica MDM. Used for vendor compliance chargeback processing and fill rate analysis.',
    `vendor_item_id` BIGINT COMMENT 'Foreign key linking to supplier.vendor_item. Business justification: Receiving teams validate received goods against the vendors item catalog (pack size, GTIN, unit cost). Linking goods_receipt to vendor_item enables discrepancy detection and chargeback eligibility as',
    `vendor_promo_agreement_id` BIGINT COMMENT 'Foreign key linking to promotion.vendor_promo_agreement. Business justification: Vendor promotional agreements specify promotional purchase quantities and delivery obligations. Linking goods receipts to vendor_promo_agreement enables performance obligation tracking, chargeback rec',
    `accepted_qty` DECIMAL(18,2) COMMENT 'Quantity of units accepted into inventory after quality inspection. Excludes rejected, damaged, or wrong-SKU units. This is the quantity inducted into on-hand inventory and used for COGS valuation.',
    `chargeback_eligible` BOOLEAN COMMENT 'Indicates whether this goods receipt record has identified discrepancies that qualify for a vendor compliance chargeback. True = chargeback may be issued to supplier; False = no chargeback applicable. Drives the vendor compliance chargeback workflow.',
    `created_timestamp` TIMESTAMP COMMENT 'System audit timestamp recording when this goods receipt record was first created in the data platform. Used for data lineage, audit trails, and SLA monitoring.',
    `currency_code` STRING COMMENT 'ISO 4217 three-letter currency code for the unit cost and total receipt cost (e.g., USD, EUR, GBP). Required for multi-currency retail operations and financial reporting.. Valid values are `^[A-Z]{3}$`',
    `discrepancy_resolution_status` STRING COMMENT 'Current status of the discrepancy resolution workflow. pending = discrepancy logged, not yet actioned; under_review = being investigated with supplier; resolved = discrepancy closed; chargeback_issued = vendor compliance chargeback raised; waived = discrepancy accepted without penalty.. Valid values are `pending|under_review|resolved|chargeback_issued|waived`',
    `discrepancy_type` STRING COMMENT 'Classification of the primary discrepancy identified during receiving. shortage = fewer units than expected; overage = more units than expected; wrong_sku = incorrect item received; damage = merchandise physically damaged; expired = past sell-by or use-by date; none = no discrepancy. Drives chargeback and resolution workflows.. Valid values are `shortage|overage|wrong_sku|damage|expired|none`',
    `expected_qty` DECIMAL(18,2) COMMENT 'Quantity of units expected at the receiving node based on the ASN or replenishment plan. May differ from ordered quantity due to partial shipments or split deliveries. Used for receiving dock planning and discrepancy detection.',
    `inspection_date` DATE COMMENT 'Date on which the quality inspection of received merchandise was completed. Used for compliance reporting, CPSC/FDA audit trails, and receiving cycle time analysis.',
    `ordered_qty` DECIMAL(18,2) COMMENT 'Quantity of units originally ordered on the purchase order line. Used as the baseline for receipt variance calculation, fill rate measurement, and vendor compliance scoring.',
    `overage_qty` DECIMAL(18,2) COMMENT 'Quantity of units received in excess of the ASN or PO expectation (received_qty minus expected_qty when positive). Overages require disposition decisions and may trigger vendor compliance chargebacks.',
    `po_number` STRING COMMENT 'Externally-known purchase order number as referenced on supplier documentation and EDI transactions. Retained for operational readability, vendor communication, and three-way match without requiring a join.',
    `quality_inspection_status` STRING COMMENT 'Status of the quality inspection performed on received merchandise. not_required = inspection waived per supplier agreement; pending = awaiting inspection; passed = all units meet quality standards; failed = units do not meet standards; partial_pass = some units accepted, some rejected. Drives accepted/rejected quantity split.. Valid values are `not_required|pending|passed|failed|partial_pass`',
    `receipt_date` DATE COMMENT 'Calendar date on which the physical goods receipt was posted. Used for inventory valuation, vendor compliance reporting, and lead time analysis. Aligns with SAP Posting Date (BUDAT) in the MM module.',
    `receipt_method` STRING COMMENT 'Method by which merchandise was physically received. dsd = Direct Store Delivery from supplier; dc_to_store = replenishment from Distribution Center; cross_dock = direct transfer without storage; drop_ship = vendor direct-to-customer; transfer_order = inter-node stock transfer. Drives receiving workflow and inventory valuation logic.. Valid values are `dsd|dc_to_store|cross_dock|drop_ship|transfer_order`',
    `receipt_notes` STRING COMMENT 'Free-text notes entered by the receiving associate documenting special conditions, discrepancy details, handling instructions, or other observations at the time of receipt. Supports discrepancy investigation and vendor communication.',
    `receipt_number` STRING COMMENT 'Externally-known business identifier for the goods receipt document, typically generated by the WMS or ERP upon physical receipt confirmation. Maps to SAP Material Document Number (MBLNR) or Manhattan WMS Receipt Number.. Valid values are `^GR-[0-9]{10}$`',
    `receipt_status` STRING COMMENT 'Current lifecycle state of the goods receipt workflow. draft indicates initiated but not confirmed; open indicates awaiting physical receipt; in_progress indicates receiving underway; completed indicates fully processed and inventory inducted; cancelled indicates voided; on_hold indicates paused pending resolution. [ENUM-REF-CANDIDATE: draft|open|in_progress|completed|cancelled|on_hold — promote to reference product]. Valid values are `draft|open|in_progress|completed|cancelled|on_hold`',
    `receipt_timestamp` TIMESTAMP COMMENT 'The principal real-world event timestamp recording when the physical merchandise was received and confirmed at the receiving node (DC, store, or MFC). Distinct from system audit timestamps. Maps to SAP Posting Date/Time in MIGO.',
    `received_qty` DECIMAL(18,2) COMMENT 'Total quantity of units physically counted and received at the dock, prior to quality inspection. Includes all units regardless of condition. Used as the gross receipt quantity for inventory induction and discrepancy calculation.',
    `receiving_node_type` STRING COMMENT 'Classification of the physical location type where goods were received. dc = Distribution Center; store = retail store; mfc = Micro-Fulfillment Center; dark_store = fulfillment-only location. Determines applicable receiving workflows and inventory induction rules.. Valid values are `dc|store|mfc|dark_store`',
    `rejected_qty` DECIMAL(18,2) COMMENT 'Quantity of units rejected during quality inspection and not inducted into inventory. Drives Return to Vendor (RTV) processing, vendor compliance chargebacks, and RMA initiation.',
    `rfid_verified` BOOLEAN COMMENT 'Indicates whether the received merchandise was verified using RFID (Radio Frequency Identification) scanning during the receiving process. True = RFID scan confirmed; False = manual or barcode-only verification. Supports inventory accuracy at point of induction.',
    `rtv_initiated` BOOLEAN COMMENT 'Indicates whether a Return to Vendor (RTV) process has been initiated for rejected units from this goods receipt. True = RTV in progress; False = no RTV initiated. Supports reverse logistics and vendor debit memo processing.',
    `shortage_qty` DECIMAL(18,2) COMMENT 'Quantity of units short-shipped relative to the ASN or PO expectation (expected_qty minus received_qty when negative). Used for vendor compliance chargeback calculation and fill rate reporting.',
    `total_receipt_cost` DECIMAL(18,2) COMMENT 'Total cost of accepted merchandise received (accepted_qty × unit_cost). Used for inventory valuation, COGS posting, and financial reconciliation. Classified as confidential due to commercial sensitivity.',
    `unit_cost` DECIMAL(18,2) COMMENT 'Cost per unit of the received merchandise as per the purchase order or supplier invoice. Used for inventory valuation (COGS), gross margin calculation (GMROI), and financial posting to the general ledger. Classified as confidential due to commercial sensitivity.',
    `upc` STRING COMMENT '12-digit Universal Product Code (UPC) barcode identifier for the received item. Used for RFID/barcode scanning during receiving, inventory accuracy validation, and GS1 compliance.. Valid values are `^[0-9]{12}$`',
    `updated_timestamp` TIMESTAMP COMMENT 'System audit timestamp recording when this goods receipt record was last modified in the data platform. Supports change tracking, discrepancy resolution audits, and data quality monitoring.',
    CONSTRAINT pk_goods_receipt PRIMARY KEY(`goods_receipt_id`)
) COMMENT 'Records physical receipt of merchandise at DCs, stores, and MFCs against purchase orders, replenishment orders, or transfer orders. Captures receipt date, receiving node, supplier/source, PO/ASN reference, line-level received/accepted/rejected quantities with discrepancy details (shortage, overage, wrong SKU, damage), unit cost, receipt method (DSD, DC-to-store, cross-dock), quality inspection status, and discrepancy resolution status. Supports receiving workflows, vendor compliance chargebacks, and inventory accuracy at point of induction.';

CREATE OR REPLACE TABLE `vibe_retail_v1`.`inventory`.`reservation` (
    `reservation_id` BIGINT COMMENT 'Unique system-generated identifier for each inventory reservation or hold record. Primary key for the reservation data product.',
    `bopis_appointment_id` BIGINT COMMENT 'Foreign key linking to fulfillment.bopis_appointment. Business justification: BOPIS reservations must be linked to their pickup appointment for SLA tracking, inventory hold expiry management, and customer notification workflows. Retail omnichannel operations require knowing whi',
    `cart_id` BIGINT COMMENT 'Foreign key linking to ecommerce.cart. Business justification: Inventory reservations are created from cart items during checkout to hold stock. Tracks cart-to-reservation lifecycle for abandoned cart inventory release and reservation expiry management.',
    `checkout_id` BIGINT COMMENT 'Foreign key linking to ecommerce.checkout. Business justification: Reservations are created during checkout to hold inventory during payment authorization. Links reservation lifecycle to checkout session for payment-hold-release coordination and checkout abandonment ',
    `corporate_account_id` DECIMAL(18,2) COMMENT 'Foreign key linking to customer.corporate_account. Business justification: B2B bulk inventory reservation process: corporate accounts reserve large quantities of inventory for business purchases (e.g., corporate gifting, bulk procurement events). This is a distinct operation',
    `fulfillment_line_id` BIGINT COMMENT 'Foreign key linking to fulfillment.fulfillment_line. Business justification: Reservations are SKU-level allocations matching fulfillment line granularity. Retail WMS systems reserve specific SKU quantities for specific order lines during wave planning and pick task generation.',
    `header_id` BIGINT COMMENT 'Reference to the customer order (OMS order) that triggered this inventory reservation. Populated for BOPIS, ROPIS, ship-from-store, and e-commerce hold encumbrances. Null for non-order-driven holds (quality, legal, regulatory). Links reservation to the order fulfillment lifecycle.',
    `inventory_node_id` BIGINT COMMENT 'System identifier for the inventory node (store, DC, MFC, dark store) where the reserved stock physically resides. Central to ATP calculation and omnichannel fulfillment routing (BOPIS, SFS, ship-from-DC).',
    `lot_id` BIGINT COMMENT 'Foreign key linking to inventory.lot. Business justification: Inventory reservations for perishable or lot-tracked items (e.g., FEFO-based omnichannel fulfillment, recall holds) must reference the specific lot being reserved. Adding lot_id to reservation enables',
    `fulfillment_order_id` BIGINT COMMENT 'Foreign key linking to fulfillment.fulfillment_order. Business justification: Inventory reservations are created during fulfillment order allocation in retail operations. When an online order or BOPIS order enters fulfillment, the WMS reserves specific inventory for that fulfil',
    `profile_id` BIGINT COMMENT 'Foreign key linking to customer.profile. Business justification: Retail omnichannel fulfillment (BOPIS, ship-from-store, curbside pickup) requires tracking which customer profile created each inventory reservation. Essential for customer service, order fulfillment,',
    `sku_id` BIGINT COMMENT 'System identifier for the SKU (Stock Keeping Unit) whose inventory is being reserved or held. Links to the product master for item-level ATP (Available to Promise) calculation and omnichannel fulfillment routing.',
    `stock_position_id` BIGINT COMMENT 'Reference to the stock_position record at the SKU-node level that this reservation encumbers. Enables direct linkage between the reservation and the ATP calculation on the stock_position product, ensuring accurate real-time inventory visibility.',
    `uom_id` BIGINT COMMENT 'Foreign key linking to product.uom. Business justification: reservation.unit_of_measure is a denormalized text field. Inventory reservations for BOPIS/ROPIS/fulfillment require validated UOM to correctly decrement available_to_promise quantities and prevent ov',
    `authorizing_department` STRING COMMENT 'Name or code of the business department that authorized the hold (e.g., Quality Assurance, Legal, Compliance, Store Operations, E-Commerce Fulfillment). Supports departmental accountability reporting and hold resolution workflows.',
    `case_reference_number` BIGINT COMMENT 'Reference to the service case, quality investigation, legal matter, or regulatory recall case that authorized a hard hold. Populated for quality_hold, legal_hold, regulatory_recall, and damage_hold encumbrance types. Links to Salesforce Service Cloud case management.',
    `created_timestamp` TIMESTAMP COMMENT 'System-generated timestamp when the reservation record was first written to the data platform (Silver layer ingestion time). Distinct from reservation_timestamp which captures the business event time. Used for data lineage and audit trail.',
    `currency_code` STRING COMMENT 'Three-letter ISO 4217 currency code for the inventory_cost_per_unit value (e.g., USD, CAD, GBP). Supports multi-currency inventory valuation for international retail operations.. Valid values are `^[A-Z]{3}$`',
    `encumbrance_type` STRING COMMENT 'Classifies the nature of the inventory encumbrance. Soft allocations (e.g., BOPIS reservation, ship-from-store allocation, e-commerce hold) are temporary and customer-driven; hard holds (quality hold, regulatory recall, legal hold, damage hold, price investigation) restrict stock from sale pending resolution. [ENUM-REF-CANDIDATE: soft_allocation|hard_hold|quality_hold|regulatory_recall|legal_hold|damage_hold|price_investigation — promote to reference product]. Valid values are `soft_allocation|hard_hold|quality_hold|regulatory_recall|legal_hold|damage_hold`',
    `expiry_timestamp` TIMESTAMP COMMENT 'Date and time at which the reservation automatically expires if not fulfilled or manually extended. Critical for BOPIS and e-commerce holds where stock must be released back to general availability after a defined window (e.g., 24–48 hours). Null for indefinite holds such as legal or regulatory holds.',
    `fiscal_period` STRING COMMENT 'Retail fiscal period (year and period number, e.g., 2024-P07) during which the reservation was created. Supports financial reporting of encumbered inventory valuation, OTB (Open to Buy) impact analysis, and period-end inventory reconciliation per FASB ASC 330.. Valid values are `^[0-9]{4}-P(0[1-9]|1[0-3])$`',
    `fulfillment_channel` STRING COMMENT 'The omnichannel fulfillment method associated with this reservation. BOPIS (Buy Online Pick Up In Store), ROPIS (Reserve Online Pick Up In Store), ship_from_store (SFS), ecommerce (ship from DC), drop_ship (vendor direct), in_store (POS hold). Null for non-order-driven hard holds.. Valid values are `bopis|ropis|ship_from_store|ecommerce|drop_ship|in_store`',
    `hold_reason_code` STRING COMMENT 'Standardized code identifying the specific business reason for the reservation or hold (e.g., BOPIS_ALLOC, SFS_ALLOC, ECOM_HOLD, QA_FAIL, RECALL_CPSC, LEGAL_HOLD, DMG_INBOUND, PRICE_INVEST). Enables operational reporting and root-cause analysis of inventory encumbrances.',
    `hold_reason_description` STRING COMMENT 'Free-text narrative describing the specific reason for the inventory hold or reservation, providing operational context beyond the structured hold_reason_code. Required for legal holds and regulatory recalls per compliance documentation standards.',
    `inventory_cost_per_unit` DECIMAL(18,2) COMMENT 'Cost of Goods Sold (COGS) per unit for the reserved SKU at the time of reservation creation. Used for financial valuation of encumbered inventory, shrinkage reporting, and GMROI (Gross Margin Return on Investment) analysis. Sourced from SAP S/4HANA Retail FI/CO module.',
    `is_recalled` BOOLEAN COMMENT 'Indicates whether this reservation was created in response to a regulatory product recall (CPSC, FDA, or other governing body). When true, the hold cannot be released without explicit compliance authorization. Supports mandatory recall reporting and quarantine workflows.',
    `is_vendor_managed` BOOLEAN COMMENT 'Indicates whether the reserved inventory is managed under a Vendor Managed Inventory (VMI) agreement, where the supplier retains ownership and replenishment responsibility. Affects financial liability and hold authorization workflows.',
    `priority_level` STRING COMMENT 'Business priority assigned to the reservation, governing queue position in fulfillment workflows and hold resolution SLAs. critical applies to regulatory recalls and legal holds; high to same-day BOPIS; standard to regular e-commerce holds; low to pre-emptive soft allocations.. Valid values are `critical|high|standard|low`',
    `release_notes` STRING COMMENT 'Free-text field capturing resolution details, disposition instructions, or compliance notes recorded at the time of hold release. Required for regulatory recalls and legal holds to document the resolution rationale for audit purposes.',
    `release_status` STRING COMMENT 'Approval workflow status for releasing a hard hold. pending — release request submitted awaiting authorization; approved — release authorized by responsible department; rejected — release denied, hold remains active; auto_released — system-triggered release upon expiry or order fulfillment; escalated — requires senior authorization.. Valid values are `pending|approved|rejected|auto_released|escalated`',
    `release_timestamp` TIMESTAMP COMMENT 'Actual date and time when the reservation was released, cancelled, or converted. Null while the reservation is active. Used for hold duration analysis, SLA compliance reporting, and ATP recalculation upon release.',
    `reservation_number` STRING COMMENT 'Externally-visible, human-readable business identifier for the reservation, used in operational communications, order management, and customer-facing references (e.g., BOPIS confirmation codes). Sourced from OMS or WMS upon creation.. Valid values are `^RES-[0-9]{10}$`',
    `reservation_status` STRING COMMENT 'Current lifecycle state of the inventory reservation. active — stock is currently encumbered; expired — reservation lapsed past expiry without fulfillment; released — hold manually or systematically lifted; cancelled — reservation voided before fulfillment; pending_release — awaiting authorization to release; converted — soft allocation fulfilled and converted to a shipment.. Valid values are `active|expired|released|cancelled|pending_release|converted`',
    `reservation_timestamp` TIMESTAMP COMMENT 'The precise date and time (with timezone offset) when the inventory encumbrance was created — the principal business event timestamp. For BOPIS/e-commerce holds, this is when the customer completed checkout. For quality/legal holds, this is when the hold was authorized.',
    `reserved_quantity` DECIMAL(18,2) COMMENT 'Number of units of the SKU encumbered by this reservation. Subtracted from on-hand quantity to derive ATP (Available to Promise) on the stock_position product. Must be positive and not exceed available on-hand at time of reservation creation.',
    `source_system_code` STRING COMMENT 'Code identifying the operational system of record that originated this reservation record (e.g., WMS = Manhattan Associates WMS, OMS = Order Management System, ECOM = Salesforce Commerce Cloud, ERP = SAP S/4HANA, MANUAL = manually entered hold). Supports data lineage and reconciliation in the Databricks Lakehouse Silver layer. [ENUM-REF-CANDIDATE: WMS|OMS|ECOM|ERP|ORMS|CAR|SFCC|MANUAL — 8 candidates stripped; promote to reference product]',
    `storage_bin` STRING COMMENT 'Specific bin, shelf, or slot location within the node where the reserved inventory is physically stored. Enables warehouse associates to locate and pick reserved stock efficiently. Sourced from Manhattan Associates WMS bin management.',
    `upc` STRING COMMENT '12-digit Universal Product Code (UPC) barcode identifier for the reserved item. Used for RFID scanning, POS reconciliation, and regulatory recall identification per GS1 standards.. Valid values are `^[0-9]{12}$`',
    `updated_timestamp` TIMESTAMP COMMENT 'System-generated timestamp of the most recent modification to the reservation record (e.g., quantity adjustment, status change, expiry extension). Used for change data capture (CDC) and incremental processing in the Databricks Lakehouse Silver layer.',
    CONSTRAINT pk_reservation PRIMARY KEY(`reservation_id`)
) COMMENT 'Records all inventory encumbrances that restrict stock from general availability — including soft-allocations (BOPIS reservation, ship-from-store allocation, e-commerce hold) and hard holds (quality hold, regulatory recall, legal hold, damage hold, price investigation). Captures encumbrance type, SKU, quantity, node, start/expiry timestamps, associated order or case reference, authorizing party, hold reason, authorizing department, release status, and resolution details. Single source of truth for all reserved and held stock, enabling accurate ATP calculation on stock_position.';

CREATE OR REPLACE TABLE `vibe_retail_v1`.`inventory`.`reorder_policy` (
    `reorder_policy_id` BIGINT COMMENT 'Unique surrogate identifier for the reorder policy record. Primary key for the reorder_policy data product in the inventory domain.',
    `cluster_id` BIGINT COMMENT 'Foreign key linking to store.cluster. Business justification: Retail replenishment policies are commonly defined at the store cluster level (e.g., all high-volume urban stores share a reorder policy). Cluster-based replenishment policy assignment is a named reta',
    `demand_forecast_id` BIGINT COMMENT 'Reference to the demand forecast record from Blue Yonder Demand Planning that drives replenishment quantity calculations for forecast_driven reorder method. Null for non-forecast-driven methods.',
    `department_id` BIGINT COMMENT 'Foreign key linking to store.department. Business justification: Reorder policies in retail are scoped to a specific department within a store (e.g., Produce has different min/max rules than Electronics). Department-level replenishment policy management is a standa',
    `inventory_node_id` BIGINT COMMENT 'Foreign key linking to inventory.inventory_node. Business justification: Reorder policies are defined at the SKU-location level, where location is an inventory node (store, DC, MFC). reorder_policy currently references inventory.location via location_id, but inventory_node is ',
    `item_hierarchy_id` BIGINT COMMENT 'Foreign key linking to product.item_hierarchy. Business justification: Retail replenishment planning sets policies at category/hierarchy level (item_hierarchy.replenishment_method, safety_stock_weeks). A reorder_policy can govern all SKUs in a hierarchy node, enabling ca',
    `lead_time_agreement_id` BIGINT COMMENT 'Foreign key linking to supplier.lead_time_agreement. Business justification: Reorder policies use lead time to calculate reorder points and safety stock. Linking to the governing lead_time_agreement ensures policy parameters stay aligned with contractual SLAs and enables autom',
    `location_id` BIGINT COMMENT 'Reference to the inventory node (store, Distribution Center (DC), or Micro-Fulfillment Center (MFC)) where this reorder policy governs stock replenishment. Combined with sku_id, forms the natural business key.',
    `promo_calendar_id` BIGINT COMMENT 'Foreign key linking to promotion.promo_calendar. Business justification: Reorder policies are adjusted for promotional periods defined in the promo_calendar (safety stock uplift, lead time compression). Linking reorder_policy to promo_calendar enables promotional replenish',
    `replenishment_plan_id` BIGINT COMMENT 'Reference to the parent replenishment plan that governs or generated this reorder policy. Links the policy to the broader supply chain planning context managed in Blue Yonder Demand Planning.',
    `sku_id` BIGINT COMMENT 'Reference to the specific SKU (Stock Keeping Unit) for which this reorder policy applies. Combined with location_id, forms the natural business key for a reorder policy.',
    `uom_id` BIGINT COMMENT 'Foreign key linking to product.uom. Business justification: reorder_policy.unit_of_measure is a denormalized text field. Reorder point quantities, MOQ, and safety stock quantities must reference the authoritative UOM to ensure replenishment calculations are co',
    `vendor_id` BIGINT COMMENT 'Reference to the preferred supplier for replenishment orders generated by this policy. Used by the replenishment engine to route purchase orders. May be overridden at order generation time if the supplier is unavailable.',
    `vendor_item_id` BIGINT COMMENT 'Foreign key linking to supplier.vendor_item. Business justification: Reorder policies are configured per SKU-vendor combination using vendor_item pack size, MOQ, and order increment. Linking reorder_policy to vendor_item enables automatic policy recalculation when vend',
    `abc_classification` STRING COMMENT 'ABC classification of the SKU at this location based on sales velocity and revenue contribution: A (high-velocity/high-value), B (medium), C (low-velocity/low-value), D (dead stock or near-dead). Influences replenishment priority, safety stock levels, and review cycle frequency.. Valid values are `A|B|C|D`',
    `approved_by` STRING COMMENT 'Name or employee identifier of the replenishment planner or manager who approved this reorder policy for activation. Supports governance, audit trail, and accountability for policy parameters.',
    `approved_timestamp` TIMESTAMP COMMENT 'The date and time when this reorder policy was formally approved for activation by the authorized planner or manager. Supports audit trail and policy lifecycle management.',
    `created_timestamp` TIMESTAMP COMMENT 'The date and time when this reorder policy record was first created in the system. Supports audit trail, data lineage, and policy lifecycle tracking.',
    `effective_date` DATE COMMENT 'The calendar date from which this reorder policy becomes active and the replenishment engine begins applying its parameters. Supports time-bound policy management and seasonal policy transitions.',
    `expiry_date` DATE COMMENT 'The calendar date after which this reorder policy is no longer active. Null indicates an open-ended policy with no planned expiration. Used to manage seasonal policies, promotional replenishment windows, and policy version transitions.',
    `is_auto_replenishment` BOOLEAN COMMENT 'Indicates whether replenishment orders are automatically generated and submitted when the reorder trigger is breached (True), or whether a replenishment planner must manually review and approve the suggested order (False).',
    `is_seasonal` BOOLEAN COMMENT 'Indicates whether this reorder policy applies seasonal adjustments to replenishment parameters (e.g., elevated safety stock or WOS targets during peak seasons). When True, seasonal override parameters may be applied by the replenishment engine.',
    `is_vendor_managed` BOOLEAN COMMENT 'Indicates whether this SKU-location replenishment is managed by the supplier under a Vendor Managed Inventory (VMI) agreement. When True, the supplier is responsible for monitoring stock levels and initiating replenishment orders rather than the retailers automated engine.',
    `last_reviewed_date` DATE COMMENT 'The most recent date on which a replenishment planner reviewed and validated the parameters of this reorder policy. Supports governance and audit of policy maintenance cadence.',
    `lead_time_days` STRING COMMENT 'The expected number of calendar days from placement of a replenishment purchase order to receipt of goods at the destination location. Used to calculate the reorder point and ensure stock does not fall below safety stock during the replenishment cycle.',
    `location_type` STRING COMMENT 'Classification of the inventory node type to which this policy applies: store (retail store), DC (Distribution Center), MFC (Micro-Fulfillment Center), dark_store (fulfillment-only location), or warehouse. Drives replenishment logic differences by node type.. Valid values are `store|dc|mfc|dark_store|warehouse`',
    `max_stock_quantity` DECIMAL(18,2) COMMENT 'The maximum allowable on-hand inventory level (in units) for this SKU at this location. Used in min/max reorder method as the upper bound. Replenishment orders are sized to bring stock up to this level without exceeding it.',
    `min_stock_quantity` DECIMAL(18,2) COMMENT 'The minimum allowable on-hand inventory level (in units) for this SKU at this location. Used in min/max reorder method as the lower bound. Stock falling below this level triggers an urgent replenishment order.',
    `moq` DECIMAL(18,2) COMMENT 'The minimum number of units that must be ordered per replenishment order as stipulated by the supplier contract. Replenishment engine enforces this floor when generating inventory_replenishment_order records.',
    `next_review_date` DATE COMMENT 'The scheduled date for the next planner review of this reorder policys parameters. Calculated from last_reviewed_date plus the review_cycle_days. Drives planner workqueue prioritization.',
    `notes` STRING COMMENT 'Free-text field for replenishment planners to document rationale for policy parameter choices, exceptions, seasonal considerations, or supplier-specific constraints associated with this reorder policy.',
    `order_multiple` DECIMAL(18,2) COMMENT 'The quantity increment in which orders must be placed, reflecting the suppliers case pack size or Minimum Order Quantity (MOQ). All replenishment order quantities are rounded up to the nearest multiple of this value to comply with supplier constraints.',
    `order_quantity` DECIMAL(18,2) COMMENT 'The fixed quantity (in units) to order each time a replenishment trigger is activated. Used for fixed_quantity reorder method. For other methods, this field may be null and the order quantity is dynamically calculated.',
    `policy_code` STRING COMMENT 'Business-facing unique alphanumeric code identifying the reorder policy, used by replenishment planners and referenced in automated replenishment engines (e.g., Blue Yonder). Externally visible identifier across systems.. Valid values are `^[A-Z0-9_-]{3,30}$`',
    `policy_name` STRING COMMENT 'Human-readable descriptive name for the reorder policy, used by replenishment planners to identify and manage policies (e.g., DC Grocery Min/Max Weekly, Store Electronics WOS-Based).',
    `policy_status` STRING COMMENT 'Current lifecycle state of the reorder policy. Controls whether the policy is actively used by the replenishment engine to generate inventory_replenishment_order records. [ENUM-REF-CANDIDATE: active|inactive|draft|pending_approval|expired|suspended — promote to reference product]. Valid values are `active|inactive|draft|pending_approval|expired|suspended`',
    `policy_version` STRING COMMENT 'Incrementing version number for this reorder policy record, incremented each time parameters are materially changed. Supports policy change history tracking and rollback capability for replenishment planners.',
    `reorder_method` STRING COMMENT 'The replenishment calculation method applied by this policy: min_max (reorder when stock falls below minimum, order up to maximum), days_of_supply (maintain a target number of days of inventory), wos_based (Weeks of Supply (WOS) target), forecast_driven (demand forecast from Blue Yonder), fixed_quantity (constant order quantity), vendor_managed (VMI — Vendor Managed Inventory where supplier controls replenishment). [ENUM-REF-CANDIDATE: min_max|days_of_supply|wos_based|forecast_driven|fixed_quantity|vendor_managed — promote to reference product]. Valid values are `min_max|days_of_supply|wos_based|forecast_driven|fixed_quantity|vendor_managed`',
    `reorder_point_quantity` DECIMAL(18,2) COMMENT 'The on-hand stock level (in units) at which a replenishment order is automatically triggered. When the stock_position in inventory falls at or below this threshold, an inventory_replenishment_order record is generated. Core parameter for min/max and fixed-quantity reorder methods.',
    `review_cycle_days` STRING COMMENT 'The frequency in calendar days at which the replenishment engine evaluates this policy and checks whether a reorder trigger has been breached. Defines the periodic review interval (e.g., daily=1, weekly=7, bi-weekly=14).',
    `safety_stock_quantity` DECIMAL(18,2) COMMENT 'Buffer stock quantity (in units) maintained above the reorder point to protect against demand variability and supply lead time uncertainty. Prevents stockouts during replenishment cycles. A key input to the reorder point calculation.',
    `source_system_code` STRING COMMENT 'Code identifying the operational system of record from which this reorder policy was originated or last updated: ORMS (Oracle Retail Merchandising System), SAP_MM (SAP S/4HANA MM Module), BLUE_YONDER (Blue Yonder Demand Planning), MANUAL (planner-entered), MDM (Informatica MDM). Supports data lineage in the Databricks Silver Layer.. Valid values are `ORMS|SAP_MM|BLUE_YONDER|MANUAL|MDM`',
    `target_days_of_supply` DECIMAL(18,2) COMMENT 'The desired number of days of inventory coverage to maintain at this location for this SKU. Used in days_of_supply reorder method to calculate the replenishment order quantity based on forecasted daily demand.',
    `target_wos` DECIMAL(18,2) COMMENT 'The desired number of weeks of inventory coverage (Weeks of Supply — WOS) to maintain at this location for this SKU. Used in wos_based reorder method. Replenishment orders are sized to achieve this WOS target based on forecasted weekly demand.',
    `updated_timestamp` TIMESTAMP COMMENT 'The date and time when this reorder policy record was most recently modified. Tracks parameter changes made by replenishment planners and supports change audit trails.',
    CONSTRAINT pk_reorder_policy PRIMARY KEY(`reorder_policy_id`)
) COMMENT 'SKU-location level replenishment parameters defining when and how much to reorder. Captures reorder method (min/max, days-of-supply, WOS-based, forecast-driven), reorder point, safety stock, min/max levels, order multiple (MOQ/case pack), lead time, review cycle, supplier preference, and policy effective/expiry dates. Trigger thresholds generate inventory_replenishment_order records when stock_position breaches defined levels. Owned and maintained by replenishment planners; consumed by automated replenishment engines.';

CREATE OR REPLACE TABLE `vibe_retail_v1`.`inventory`.`lot` (
    `lot_id` BIGINT COMMENT 'Unique identifier for the inventory lot or batch record. Primary key for the lot entity.',
    `cost_price_id` BIGINT COMMENT 'Foreign key linking to pricing.cost_price. Business justification: Lot-level costing for FEFO/FIFO valuation and batch-specific cost tracking. Perishables, pharmaceuticals, and regulated products require lot-specific cost basis for accurate inventory valuation, recal',
    `goods_receipt_id` BIGINT COMMENT 'Reference to the goods receipt transaction that brought this lot into inventory. Links to receiving documentation.',
    `gtin_registry_id` BIGINT COMMENT 'Foreign key linking to product.gtin_registry. Business justification: lot.gtin is a denormalized text field. Lot traceability for recall management (lot.is_recalled, recall_reference_number) requires linking to the authoritative product.gtin_registry for GTIN validation',
    `inventory_node_id` BIGINT COMMENT 'Foreign key linking to inventory.inventory_node. Business justification: A lot/batch is physically stored at an inventory node. lot currently has storage_location_code (a string bin/zone reference) but no FK to the inventory node where the lot resides. Adding inventory_nod',
    `parent_lot_id` BIGINT COMMENT 'Self-referencing FK on lot (parent_lot_id)',
    `purchase_order_id` BIGINT COMMENT 'Reference to the purchase order that sourced this lot. Links lot traceability to procurement records.',
    `sku_id` BIGINT COMMENT 'Reference to the product SKU that this lot represents. Links lot-level tracking to product master data.',
    `uom_id` BIGINT COMMENT 'Foreign key linking to product.uom. Business justification: lot.unit_of_measure is a denormalized text field. Lot-level quantity tracking (available_quantity, quantity) for FEFO rotation, expiry management, and recall traceability requires validated UOM from p',
    `vendor_id` BIGINT COMMENT 'Reference to the supplier or vendor who provided this lot. Critical for recall management and vendor performance tracking.',
    `vendor_item_id` BIGINT COMMENT 'Foreign key linking to supplier.vendor_item. Business justification: Lot traceability and product recall management require knowing which vendor item a lot originated from. Retail quality and food safety teams trace lots back to the vendors specific item catalog entry',
    `available_quantity` DECIMAL(18,2) COMMENT 'Current quantity available for sale or allocation from this lot. Decreases as units are sold or reserved.',
    `batch_number` STRING COMMENT 'Manufacturer or supplier assigned batch identifier. May differ from internal lot number for vendor-managed inventory scenarios.',
    `best_before_date` DATE COMMENT 'Date indicating optimal quality period. Product may still be safe after this date but quality may degrade. Distinct from expiry date.',
    `certification_code` STRING COMMENT 'Product certification or compliance code for the lot. Examples: organic, kosher, halal, fair trade, non-GMO. Supports labeling and marketing claims.',
    `country_of_origin` STRING COMMENT 'Three-letter ISO country code indicating where the product was manufactured or grown. Required for customs and labeling compliance.. Valid values are `^[A-Z]{3}$`',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when the lot record was first created in the system. Audit trail for data lineage and compliance reporting.',
    `currency_code` STRING COMMENT 'Three-letter ISO currency code for unit cost. Standard codes include USD, EUR, GBP, CAD, etc.. Valid values are `^[A-Z]{3}$`',
    `expiry_date` DATE COMMENT 'Date when the product lot expires and should no longer be sold or consumed. Mandatory for perishable goods and pharmaceuticals.',
    `fefo_sequence` STRING COMMENT 'Sequence number for FEFO picking logic. Lower numbers indicate earlier expiry and should be picked first to minimize waste.',
    `inspection_date` DATE COMMENT 'Date when quality inspection was performed on the lot. Required for compliance with food safety and product safety regulations.',
    `inspection_result` STRING COMMENT 'Detailed outcome or notes from the quality inspection process. Captures defects, non-conformances, or approval notes.',
    `is_private_label` BOOLEAN COMMENT 'Indicates whether this lot is a private label or store brand product. True if private label; false if national brand.',
    `is_recalled` BOOLEAN COMMENT 'Indicates whether this lot is subject to a product recall. True if recalled; false otherwise. Triggers immediate hold and customer notification.',
    `is_vendor_managed` BOOLEAN COMMENT 'Indicates whether this lot is part of a vendor-managed inventory agreement. True if VMI; false if retailer-owned.',
    `lot_number` STRING COMMENT 'Business identifier for the lot or batch. Human-readable code used for tracking and traceability across the supply chain.',
    `lot_status` STRING COMMENT 'Current lifecycle status of the lot. Determines whether the lot is available for sale, held for quality inspection, or restricted. [ENUM-REF-CANDIDATE: available|quarantine|hold|released|expired|recalled|disposed — 7 candidates stripped; promote to reference product]',
    `manufacture_date` DATE COMMENT 'Date when the product lot was manufactured or produced. Critical for shelf life calculation and food safety compliance.',
    `notes` STRING COMMENT 'Free-text notes or comments about the lot. Captures special handling instructions, quality observations, or operational remarks.',
    `quality_status` STRING COMMENT 'Quality inspection outcome for the lot. Approved lots are available for sale; rejected lots must be returned or disposed.. Valid values are `pending|approved|rejected|conditional`',
    `quantity` DECIMAL(18,2) COMMENT 'Total quantity of units in the lot at receipt. Used for inventory valuation and traceability reporting.',
    `recall_reference_number` STRING COMMENT 'Official recall case or reference number issued by regulatory authority or manufacturer. Links to recall management system.',
    `receipt_date` DATE COMMENT 'Date when the lot was received into inventory at the destination node. Used for aging analysis and FEFO sequencing.',
    `remaining_shelf_life_days` STRING COMMENT 'Number of days remaining until expiry as of the current date. Calculated field used for near-expiry alerts and markdown triggers.',
    `shelf_life_days` STRING COMMENT 'Total shelf life of the product in days from manufacture date to expiry date. Used for aging analysis and markdown planning.',
    `source_system_code` STRING COMMENT 'Identifier of the operational system that created or owns this lot record. Examples: WMS, ERP, MDM. Supports data lineage and reconciliation.',
    `storage_location_code` STRING COMMENT 'Warehouse bin, zone, or storage location where the lot is physically stored. Supports pick/pack operations and cycle counting.',
    `supplier_lot_reference` STRING COMMENT 'Suppliers original lot or batch identifier. Used for traceability back to the suppliers manufacturing records.',
    `temperature_zone` STRING COMMENT 'Required storage temperature zone for the lot. Critical for cold chain compliance and food safety.. Valid values are `ambient|refrigerated|frozen|controlled`',
    `unit_cost` DECIMAL(18,2) COMMENT 'Cost per unit for this lot. Used for inventory valuation and cost of goods sold calculation. May vary by lot due to pricing changes.',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp when the lot record was last modified. Tracks changes to lot status, quantity, or other attributes for audit purposes.',
    CONSTRAINT pk_lot PRIMARY KEY(`lot_id`)
) COMMENT 'Master record for inventory lot/batch tracking at the SKU level. Captures lot number, manufacture date, expiry date, supplier lot reference, and quality status. Supports traceability for food safety (FDA FSMA) and recall management.';

